// it A1-B1 grammar cheat-sheet (auto-assembled).
const GRAMMAR = [
{"id":"alfabeto-pronuncia","icon":"🔤","level":"A1","title":{"it":"Alfabeto e pronuncia","ru":"Алфавит и произношение","de":"Alphabet und Aussprache","en":"Alphabet & pronunciation","uk":"Алфавіт і вимова","fa":"الفبا و تلفظ"},"intro":{"it":"L'alfabeto italiano ha 21 lettere. La pronuncia è quasi sempre regolare: si legge come si scrive. Attenzione ai suoni di c e g (duri o dolci), ai digrammi gli, gn, sc e alle consonanti doppie.","ru":"В итальянском алфавите 21 буква. Произношение почти всегда регулярное: читается как пишется. Обратите внимание на звуки c и g (твёрдые или мягкие), на буквосочетания gli, gn, sc и на двойные согласные.","de":"Das italienische Alphabet hat 21 Buchstaben. Die Aussprache ist fast immer regelmäßig: Man liest, wie man schreibt. Achte auf die Laute von c und g (hart oder weich), auf die Digraphen gli, gn, sc und auf die Doppelkonsonanten.","en":"The Italian alphabet has 21 letters. Pronunciation is almost always regular: you read it as it is written. Watch out for the sounds of c and g (hard or soft), the digraphs gli, gn, sc and double consonants.","uk":"В італійському алфавіті 21 літера. Вимова майже завжди регулярна: читається так, як пишеться. Зверніть увагу на звуки c і g (тверді чи м'які), на буквосполучення gli, gn, sc та на подвоєні приголосні.","fa":"الفبای ایتالیایی ۲۱ حرف دارد. تلفظ تقریباً همیشه قاعده‌مند است: همان‌طور که نوشته می‌شود خوانده می‌شود. به صداهای c و g (سخت یا نرم)، به دوحرفی‌های gli، gn، sc و به صامت‌های مضاعف توجه کنید."},"tables":[{"caption":{"it":"Suoni particolari","ru":"Особые звуки","de":"Besondere Laute","en":"Special sounds","uk":"Особливі звуки","fa":"صداهای خاص"},"labelHeader":{"it":"Lettere","ru":"Буквы","de":"Buchstaben","en":"Letters","uk":"Літери","fa":"حروف"},"columns":[{"it":"Suono","ru":"Звук","de":"Laut","en":"Sound","uk":"Звук","fa":"صدا"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"c + a/o/u","ru":"c + a/o/u","de":"c + a/o/u","en":"c + a/o/u","uk":"c + a/o/u","fa":"c + a/o/u"},"cells":["/k/ dura","casa, come, cubo"]},{"label":{"it":"c + e/i","ru":"c + e/i","de":"c + e/i","en":"c + e/i","uk":"c + e/i","fa":"c + e/i"},"cells":["/tʃ/ dolce","cena, città"]},{"label":{"it":"ch, gh","ru":"ch, gh","de":"ch, gh","en":"ch, gh","uk":"ch, gh","fa":"ch, gh"},"cells":["/k/, /g/ dure","che, chi, ghiro"]},{"label":{"it":"g + e/i","ru":"g + e/i","de":"g + e/i","en":"g + e/i","uk":"g + e/i","fa":"g + e/i"},"cells":["/dʒ/ dolce","gelato, giro"]},{"label":{"it":"gli","ru":"gli","de":"gli","en":"gli","uk":"gli","fa":"gli"},"cells":["/ʎ/ palatale","figlio, gli, moglie"]},{"label":{"it":"gn","ru":"gn","de":"gn","en":"gn","uk":"gn","fa":"gn"},"cells":["/ɲ/ palatale","gnocchi, bagno"]},{"label":{"it":"sc + e/i","ru":"sc + e/i","de":"sc + e/i","en":"sc + e/i","uk":"sc + e/i","fa":"sc + e/i"},"cells":["/ʃ/","scena, pesce"]},{"label":{"it":"z","ru":"z","de":"z","en":"z","uk":"z","fa":"z"},"cells":["/ts/ o /dz/","pizza, zero"]}]},{"caption":{"it":"Accento e consonanti doppie","ru":"Ударение и двойные согласные","de":"Betonung und Doppelkonsonanten","en":"Stress and double consonants","uk":"Наголос і подвоєні приголосні","fa":"تکیه و صامت‌های مضاعف"},"labelHeader":{"it":"Aspetto","ru":"Явление","de":"Aspekt","en":"Feature","uk":"Явище","fa":"ویژگی"},"columns":[{"it":"Descrizione","ru":"Описание","de":"Beschreibung","en":"Description","uk":"Опис","fa":"توضیح"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"Accento tonico","ru":"Тоническое ударение","de":"Wortbetonung","en":"Word stress","uk":"Тонічний наголос","fa":"تکیهٔ کلمه"},"cells":["di solito sulla penultima sillaba","aMIco, taVOlo"]},{"label":{"it":"Accento scritto","ru":"Письменное ударение","de":"Schriftlicher Akzent","en":"Written accent","uk":"Письмовий наголос","fa":"تکیهٔ نوشتاری"},"cells":["obbligatorio sulle parole tronche","città, perché, caffè"]},{"label":{"it":"Consonanti doppie","ru":"Двойные согласные","de":"Doppelkonsonanten","en":"Double consonants","uk":"Подвоєні приголосні","fa":"صامت‌های مضاعف"},"cells":["suono più lungo e intenso","nonno, palla, ferro"]}]}],"examples":[{"it":"L'alfabeto italiano ha ventuno lettere.","ru":"В итальянском алфавите двадцать одна буква.","de":"Das italienische Alphabet hat einundzwanzig Buchstaben.","en":"The Italian alphabet has twenty-one letters.","uk":"В італійському алфавіті двадцять одна літера.","fa":"الفبای ایتالیایی بیست و یک حرف دارد."},{"it":"La parola «gnocchi» si pronuncia con il suono /ɲ/.","ru":"Слово «gnocchi» произносится со звуком /ɲ/.","de":"Das Wort „gnocchi“ wird mit dem Laut /ɲ/ ausgesprochen.","en":"The word “gnocchi” is pronounced with the /ɲ/ sound.","uk":"Слово «gnocchi» вимовляється зі звуком /ɲ/.","fa":"کلمهٔ «gnocchi» با صدای /ɲ/ تلفظ می‌شود."},{"it":"Attenzione: «nono» e «nonno» hanno significati diversi.","ru":"Внимание: «nono» и «nonno» имеют разные значения.","de":"Achtung: „nono“ und „nonno“ haben unterschiedliche Bedeutungen.","en":"Careful: “nono” and “nonno” have different meanings.","uk":"Увага: «nono» та «nonno» мають різні значення.","fa":"توجه: «nono» و «nonno» معانی متفاوتی دارند."}],"hints":{"ru":"В отличие от русского, двойные согласные в итальянском действительно удлиняются — «nonno» звучит дольше «nono». Буква c перед e/i читается как «ч», а не «ц».","de":"Anders als im Deutschen wird «c» vor e/i wie «tsch» gesprochen und «z» oft wie «ts/dz». Doppelkonsonanten wirklich lang aussprechen (nonno).","en":"Unlike English, «c» before e/i is «ch» (cena = chena), «gli» is a single palatal sound, and double consonants are really held longer.","uk":"На відміну від української, подвоєні приголосні вимовляються довше; «c» перед e/i читається як «ч», а «gn» — як м'яке «нь».","fa":"برخلاف فارسی، حروف مضاعف واقعاً کشیده تلفظ می‌شوند؛ «c» پیش از e/i مانند «چ» و «gn» مانند «نی» خوانده می‌شود."}},
{"id":"articoli-genere","icon":"🚻","level":"A1","title":{"it":"Articoli, genere e numero","ru":"Артикли, род и число","de":"Artikel, Genus und Numerus","en":"Articles, gender & number","uk":"Артиклі, рід і число","fa":"حروف تعریف، جنس و شمار"},"intro":{"it":"In italiano ogni nome è maschile o femminile e ha un articolo. L'articolo determinativo (il, lo, la, l', i, gli, le) e indeterminativo (un, uno, una, un') cambia secondo il genere, il numero e il suono iniziale della parola che segue.","ru":"В итальянском каждое существительное мужского или женского рода и требует артикля. Определённый (il, lo, la, l', i, gli, le) и неопределённый (un, uno, una, un') артикль меняется в зависимости от рода, числа и начального звука следующего слова.","de":"Im Italienischen ist jedes Substantiv männlich oder weiblich und hat einen Artikel. Der bestimmte (il, lo, la, l', i, gli, le) und der unbestimmte Artikel (un, uno, una, un') richtet sich nach Genus, Numerus und dem Anfangslaut des folgenden Wortes.","en":"In Italian every noun is masculine or feminine and takes an article. The definite (il, lo, la, l', i, gli, le) and indefinite article (un, uno, una, un') changes according to gender, number and the initial sound of the following word.","uk":"В італійській кожен іменник чоловічого або жіночого роду й потребує артикля. Означений (il, lo, la, l', i, gli, le) та неозначений (un, uno, una, un') артикль змінюється залежно від роду, числа й початкового звука наступного слова.","fa":"در ایتالیایی هر اسم مذکر یا مؤنث است و حرف تعریف می‌گیرد. حرف تعریف معرفه (il، lo، la، l'، i، gli، le) و نکره (un، uno، una، un') بر پایهٔ جنس، شمار و صدای آغازین کلمهٔ بعد تغییر می‌کند."},"tables":[{"caption":{"it":"Articoli determinativi","ru":"Определённые артикли","de":"Bestimmte Artikel","en":"Definite articles","uk":"Означені артиклі","fa":"حروف تعریف معرفه"},"labelHeader":{"it":"Genere e inizio della parola","ru":"Род и начало слова","de":"Genus und Wortanfang","en":"Gender and word beginning","uk":"Рід і початок слова","fa":"جنس و آغاز کلمه"},"columns":[{"it":"Singolare","ru":"Единственное число","de":"Singular","en":"Singular","uk":"Однина","fa":"مفرد"},{"it":"Plurale","ru":"Множественное число","de":"Plural","en":"Plural","uk":"Множина","fa":"جمع"}],"rows":[{"label":{"it":"Maschile + consonante","ru":"Мужской + согласная","de":"Maskulin + Konsonant","en":"Masculine + consonant","uk":"Чоловічий + приголосна","fa":"مذکر + صامت"},"cells":["il libro","i libri"]},{"label":{"it":"Maschile + s+cons., z, gn, ps","ru":"Мужской + s+согл., z, gn, ps","de":"Maskulin + s+Kons., z, gn, ps","en":"Masculine + s+cons., z, gn, ps","uk":"Чоловічий + s+приг., z, gn, ps","fa":"مذکر + s+صامت، z، gn، ps"},"cells":["lo studente","gli studenti"]},{"label":{"it":"Maschile + vocale","ru":"Мужской + гласная","de":"Maskulin + Vokal","en":"Masculine + vowel","uk":"Чоловічий + голосна","fa":"مذکر + مصوت"},"cells":["l'amico","gli amici"]},{"label":{"it":"Femminile + consonante","ru":"Женский + согласная","de":"Feminin + Konsonant","en":"Feminine + consonant","uk":"Жіночий + приголосна","fa":"مؤنث + صامت"},"cells":["la casa","le case"]},{"label":{"it":"Femminile + vocale","ru":"Женский + гласная","de":"Feminin + Vokal","en":"Feminine + vowel","uk":"Жіночий + голосна","fa":"مؤنث + مصوت"},"cells":["l'amica","le amiche"]}]},{"caption":{"it":"Articoli indeterminativi","ru":"Неопределённые артикли","de":"Unbestimmte Artikel","en":"Indefinite articles","uk":"Неозначені артиклі","fa":"حروف تعریف نکره"},"labelHeader":{"it":"Contesto","ru":"Контекст","de":"Kontext","en":"Context","uk":"Контекст","fa":"بافت"},"columns":[{"it":"Articolo","ru":"Артикль","de":"Artikel","en":"Article","uk":"Артикль","fa":"حرف تعریف"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"Maschile + consonante/vocale","ru":"Мужской + согласная/гласная","de":"Maskulin + Konsonant/Vokal","en":"Masculine + consonant/vowel","uk":"Чоловічий + приголосна/голосна","fa":"مذکر + صامت/مصوت"},"cells":["un","un libro, un amico"]},{"label":{"it":"Maschile + s+cons., z, gn","ru":"Мужской + s+согл., z, gn","de":"Maskulin + s+Kons., z, gn","en":"Masculine + s+cons., z, gn","uk":"Чоловічий + s+приг., z, gn","fa":"مذکر + s+صامت، z، gn"},"cells":["uno","uno studente, uno zaino"]},{"label":{"it":"Femminile + consonante","ru":"Женский + согласная","de":"Feminin + Konsonant","en":"Feminine + consonant","uk":"Жіночий + приголосна","fa":"مؤنث + صامت"},"cells":["una","una casa"]},{"label":{"it":"Femminile + vocale","ru":"Женский + гласная","de":"Feminin + Vokal","en":"Feminine + vowel","uk":"Жіночий + голосна","fa":"مؤنث + مصوت"},"cells":["un'","un'amica"]}]}],"examples":[{"it":"Il gatto è nero, la casa è grande.","ru":"Кот чёрный, дом большой.","de":"Der Kater ist schwarz, das Haus ist groß.","en":"The cat is black, the house is big.","uk":"Кіт чорний, будинок великий.","fa":"گربه سیاه است، خانه بزرگ است."},{"it":"Ho comprato uno zaino e un'automobile.","ru":"Я купил рюкзак и машину.","de":"Ich habe einen Rucksack und ein Auto gekauft.","en":"I bought a backpack and a car.","uk":"Я купив рюкзак і автомобіль.","fa":"یک کوله‌پشتی و یک اتومبیل خریدم."},{"it":"I bambini giocano con gli amici.","ru":"Дети играют с друзьями.","de":"Die Kinder spielen mit den Freunden.","en":"The children play with their friends.","uk":"Діти граються з друзями.","fa":"بچه‌ها با دوستان بازی می‌کنند."}],"hints":{"ru":"В итальянском у существительных есть род (м/ж), но нет среднего, как в русском. Артикль обязателен и зависит от первой буквы следующего слова: lo/gli/uno перед s+согласный, z, gn.","de":"Anders als im Deutschen gibt es nur zwei Genera (kein Neutrum). Der Artikel richtet sich nach dem Anfangslaut des folgenden Wortes: lo/uno vor s+Konsonant, z, gn, ps.","en":"Unlike English, articles agree in gender and number and depend on the first sound of the next word (lo/gli/uno before s+consonant, z, gn). L' and un' are elided before vowels.","uk":"На відміну від української, артикль обов'язковий і залежить від першого звука наступного слова: lo/gli/uno перед s+приголосний, z, gn.","fa":"برخلاف فارسی که حرف تعریف ندارد، در ایتالیایی حرف تعریف الزامی است و با جنس، شمار و صدای آغازین کلمهٔ بعد تغییر می‌کند (lo/gli/uno پیش از s+صامت، z، gn)."}},
{"id":"pronomi-soggetto","icon":"🫵","level":"A1","title":{"it":"Pronomi personali soggetto","ru":"Личные местоимения-подлежащие","de":"Personalpronomen (Subjekt)","en":"Subject pronouns","uk":"Особові займенники-підмети","fa":"ضمایر فاعلی"},"intro":{"it":"I pronomi soggetto sono io, tu, lui, lei, noi, voi, loro. In italiano si usano soprattutto per enfasi o chiarezza, perché la desinenza del verbo indica già la persona. Per la cortesia si usa Lei (con il verbo alla terza persona singolare).","ru":"Местоимения-подлежащие: io, tu, lui, lei, noi, voi, loro. В итальянском их используют в основном для акцента или ясности, потому что окончание глагола уже указывает на лицо. Для вежливости используется Lei (с глаголом в 3-м лице ед. ч.).","de":"Die Subjektpronomen sind io, tu, lui, lei, noi, voi, loro. Im Italienischen benutzt man sie vor allem zur Betonung oder Klarheit, denn die Verbendung zeigt die Person schon an. Höflich verwendet man Lei (mit dem Verb in der 3. Person Singular).","en":"The subject pronouns are io, tu, lui, lei, noi, voi, loro. In Italian they are used mainly for emphasis or clarity, because the verb ending already shows the person. For politeness you use Lei (with the verb in the third person singular).","uk":"Займенники-підмети: io, tu, lui, lei, noi, voi, loro. В італійській їх вживають переважно для наголосу чи ясності, бо закінчення дієслова вже вказує на особу. Для ввічливості вживають Lei (з дієсловом у 3-й особі однини).","fa":"ضمایر فاعلی عبارت‌اند از io، tu، lui، lei، noi، voi، loro. در ایتالیایی بیشتر برای تأکید یا روشنی به کار می‌روند، زیرا شناسهٔ فعل خودش شخص را نشان می‌دهد. برای احترام از Lei استفاده می‌شود (با فعل سوم‌شخص مفرد)."},"tables":[{"caption":{"it":"Pronomi soggetto","ru":"Местоимения-подлежащие","de":"Subjektpronomen","en":"Subject pronouns","uk":"Займенники-підмети","fa":"ضمایر فاعلی"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Singolare","ru":"Единственное число","de":"Singular","en":"Singular","uk":"Однина","fa":"مفرد"},{"it":"Plurale","ru":"Множественное число","de":"Plural","en":"Plural","uk":"Множина","fa":"جمع"}],"rows":[{"label":{"it":"1ª persona","ru":"1-е лицо","de":"1. Person","en":"1st person","uk":"1-ша особа","fa":"اول‌شخص"},"cells":["io","noi"]},{"label":{"it":"2ª persona","ru":"2-е лицо","de":"2. Person","en":"2nd person","uk":"2-га особа","fa":"دوم‌شخص"},"cells":["tu","voi"]},{"label":{"it":"3ª persona maschile","ru":"3-е лицо, мужской род","de":"3. Person maskulin","en":"3rd person masculine","uk":"3-тя особа, чоловічий рід","fa":"سوم‌شخص مذکر"},"cells":["lui","loro"]},{"label":{"it":"3ª persona femminile","ru":"3-е лицо, женский род","de":"3. Person feminin","en":"3rd person feminine","uk":"3-тя особа, жіночий рід","fa":"سوم‌شخص مؤنث"},"cells":["lei","loro"]},{"label":{"it":"Forma di cortesia","ru":"Вежливая форма","de":"Höflichkeitsform","en":"Polite form","uk":"Ввічлива форма","fa":"صورت محترمانه"},"cells":["Lei","voi / Loro"]}]},{"caption":{"it":"Tu o Lei?","ru":"Tu или Lei?","de":"Tu oder Lei?","en":"Tu or Lei?","uk":"Tu чи Lei?","fa":"Tu یا Lei؟"},"labelHeader":{"it":"Situazione","ru":"Ситуация","de":"Situation","en":"Situation","uk":"Ситуація","fa":"موقعیت"},"columns":[{"it":"Pronome","ru":"Местоимение","de":"Pronomen","en":"Pronoun","uk":"Займенник","fa":"ضمیر"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"Con amici e familiari","ru":"С друзьями и семьёй","de":"Mit Freunden und Familie","en":"With friends and family","uk":"З друзями та родиною","fa":"با دوستان و خانواده"},"cells":["tu","Tu come stai?"]},{"label":{"it":"In contesti formali","ru":"В формальной обстановке","de":"In formellen Situationen","en":"In formal contexts","uk":"У формальних ситуаціях","fa":"در موقعیت‌های رسمی"},"cells":["Lei","Lei come sta?"]},{"label":{"it":"Rivolgendosi a più persone","ru":"Обращаясь к нескольким людям","de":"An mehrere Personen gerichtet","en":"Addressing several people","uk":"Звертаючись до кількох людей","fa":"خطاب به چند نفر"},"cells":["voi","Voi come state?"]}]}],"examples":[{"it":"Io sono italiano, tu sei tedesco.","ru":"Я итальянец, ты немец.","de":"Ich bin Italiener, du bist Deutscher.","en":"I am Italian, you are German.","uk":"Я італієць, ти німець.","fa":"من ایتالیایی هستم، تو آلمانی هستی."},{"it":"Signora, Lei come si chiama?","ru":"Синьора, как Вас зовут?","de":"Gnädige Frau, wie heißen Sie?","en":"Madam, what is your name?","uk":"Пані, як Вас звати?","fa":"خانم، اسم شما چیست؟"},{"it":"Noi studiamo, ma loro lavorano.","ru":"Мы учимся, а они работают.","de":"Wir lernen, aber sie arbeiten.","en":"We study, but they work.","uk":"Ми навчаємося, а вони працюють.","fa":"ما درس می‌خوانیم، اما آن‌ها کار می‌کنند."}],"hints":{"ru":"В итальянском местоимение-подлежащее обычно опускается, потому что окончание глагола уже указывает на лицо: «sono» = «я есть». Вежливое «Lei» пишется с большой буквы и требует глагол 3-го лица ед. ч.","de":"Anders als im Deutschen lässt man das Subjektpronomen meist weg (die Endung zeigt die Person). Höfliches «Lei» steht mit der 3. Person Singular, nicht wie deutsches «Sie» (3. Plural).","en":"Unlike English, subject pronouns are usually dropped because the verb ending shows the person. Polite «Lei» takes the third-person singular and is often capitalized.","uk":"На відміну від української, займенник-підмет зазвичай опускають — закінчення дієслова вказує на особу. Ввічливе «Lei» вживається з дієсловом 3-ї особи однини.","fa":"برخلاف فارسی، ضمیر فاعلی معمولاً حذف می‌شود چون شناسهٔ فعل شخص را نشان می‌دهد. «Lei» محترمانه با فعل سوم‌شخص مفرد می‌آید."}},
{"id":"presente-indicativo","icon":"⏱️","level":"A1","title":{"it":"Presente indicativo","ru":"Настоящее время (indicativo)","de":"Präsens (Indikativ)","en":"Present tense (indicative)","uk":"Теперішній час (indicativo)","fa":"زمان حال اخباری"},"intro":{"it":"Il presente indicativo esprime azioni abituali o in corso. I verbi regolari seguono tre coniugazioni: -are, -ere, -ire (alcuni -ire aggiungono -isc-, come finire). Essere e avere e altri verbi comuni sono irregolari.","ru":"Настоящее время выражает привычные или происходящие сейчас действия. Правильные глаголы делятся на три спряжения: -are, -ere, -ire (некоторые -ire добавляют -isc-, например finire). Essere и avere и другие частые глаголы неправильные.","de":"Das Präsens drückt gewohnheitsmäßige oder gerade ablaufende Handlungen aus. Die regelmäßigen Verben folgen drei Konjugationen: -are, -ere, -ire (einige -ire fügen -isc- ein, z. B. finire). Essere und avere und weitere häufige Verben sind unregelmäßig.","en":"The present indicative expresses habitual or ongoing actions. Regular verbs follow three conjugations: -are, -ere, -ire (some -ire add -isc-, like finire). Essere and avere and other common verbs are irregular.","uk":"Теперішній час виражає звичні або триваючі зараз дії. Правильні дієслова мають три дієвідміни: -are, -ere, -ire (деякі -ire додають -isc-, як finire). Essere й avere та інші поширені дієслова неправильні.","fa":"زمان حال اخباری کارهای عادتی یا در حال انجام را بیان می‌کند. افعال باقاعده سه صرف دارند: -are، -ere، -ire (برخی -ire جزء -isc- می‌گیرند، مانند finire). essere و avere و دیگر افعال پرکاربرد بی‌قاعده‌اند."},"tables":[{"caption":{"it":"Verbi regolari","ru":"Правильные глаголы","de":"Regelmäßige Verben","en":"Regular verbs","uk":"Правильні дієслова","fa":"افعال باقاعده"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"-are (parlare)","ru":"-are (parlare)","de":"-are (parlare)","en":"-are (parlare)","uk":"-are (parlare)","fa":"-are (parlare)"},{"it":"-ere (prendere)","ru":"-ere (prendere)","de":"-ere (prendere)","en":"-ere (prendere)","uk":"-ere (prendere)","fa":"-ere (prendere)"},{"it":"-ire (dormire)","ru":"-ire (dormire)","de":"-ire (dormire)","en":"-ire (dormire)","uk":"-ire (dormire)","fa":"-ire (dormire)"},{"it":"-ire -isc (finire)","ru":"-ire -isc (finire)","de":"-ire -isc (finire)","en":"-ire -isc (finire)","uk":"-ire -isc (finire)","fa":"-ire -isc (finire)"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["parlo","prendo","dormo","finisco"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["parli","prendi","dormi","finisci"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["parla","prende","dorme","finisce"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["parliamo","prendiamo","dormiamo","finiamo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["parlate","prendete","dormite","finite"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["parlano","prendono","dormono","finiscono"]}]},{"caption":{"it":"Verbi irregolari comuni","ru":"Частые неправильные глаголы","de":"Häufige unregelmäßige Verben","en":"Common irregular verbs","uk":"Поширені неправильні дієслова","fa":"افعال بی‌قاعدهٔ پرکاربرد"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"essere","ru":"essere (быть)","de":"essere (sein)","en":"essere (to be)","uk":"essere (бути)","fa":"essere (بودن)"},{"it":"avere","ru":"avere (иметь)","de":"avere (haben)","en":"avere (to have)","uk":"avere (мати)","fa":"avere (داشتن)"},{"it":"fare","ru":"fare (делать)","de":"fare (machen)","en":"fare (to do)","uk":"fare (робити)","fa":"fare (انجام دادن)"},{"it":"andare","ru":"andare (идти)","de":"andare (gehen)","en":"andare (to go)","uk":"andare (йти)","fa":"andare (رفتن)"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["sono","ho","faccio","vado"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["sei","hai","fai","vai"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["è","ha","fa","va"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["siamo","abbiamo","facciamo","andiamo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["siete","avete","fate","andate"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["sono","hanno","fanno","vanno"]}]}],"examples":[{"it":"Io parlo italiano e tu capisci tutto.","ru":"Я говорю по-итальянски, а ты всё понимаешь.","de":"Ich spreche Italienisch und du verstehst alles.","en":"I speak Italian and you understand everything.","uk":"Я розмовляю італійською, а ти все розумієш.","fa":"من ایتالیایی صحبت می‌کنم و تو همه چیز را می‌فهمی."},{"it":"Noi abbiamo fame e andiamo al ristorante.","ru":"Мы голодны и идём в ресторан.","de":"Wir haben Hunger und gehen ins Restaurant.","en":"We are hungry and we are going to the restaurant.","uk":"Ми голодні й ідемо до ресторану.","fa":"ما گرسنه هستیم و به رستوران می‌رویم."},{"it":"Loro finiscono il lavoro e poi dormono.","ru":"Они заканчивают работу, а потом спят.","de":"Sie beenden die Arbeit und schlafen dann.","en":"They finish the work and then sleep.","uk":"Вони завершують роботу, а потім сплять.","fa":"آن‌ها کار را تمام می‌کنند و بعد می‌خوابند."}],"hints":{"ru":"«Avere» (иметь) используется там, где русский говорит «мне ... лет / я голоден»: ho fame, ho vent'anni. Многие глаголы на -ire добавляют -isc- (finisco). Одно настоящее время передаёт и «делаю», и «делаю сейчас».","de":"«Avere» drückt Zustände aus, wo Deutsch «sein» nutzt: ho fame (ich habe Hunger). Viele -ire-Verben schieben -isc- ein (finisco). Ein Präsens deckt «ich mache» und «ich bin dabei zu machen» ab.","en":"Italian «avere» (to have) is used where English uses «to be»: ho fame = I am hungry. Many -ire verbs insert -isc- (finisco). One present tense covers both «I do» and «I am doing».","uk":"«Avere» (мати) вживають там, де українська каже «мені ... років / я голодний»: ho fame. Багато дієслів на -ire додають -isc- (finisco). Один теперішній час передає і «роблю», і «роблю зараз».","fa":"«Avere» (داشتن) جایی به کار می‌رود که فارسی «گرسنه بودن» می‌گوید: ho fame یعنی گرسنه‌ام. بسیاری از افعال -ire جزء -isc- می‌گیرند (finisco). یک زمان حال هم «انجام می‌دهم» و هم «در حال انجامم» را می‌رساند."}},
{"id":"aggettivi","icon":"🎨","level":"A1","title":{"it":"Gli aggettivi: accordo e posizione","ru":"Прилагательные: согласование и место","de":"Adjektive: Angleichung und Stellung","en":"Adjectives: agreement and position","uk":"Прикметники: узгодження та місце","fa":"صفت‌ها: مطابقت و جایگاه"},"intro":{"it":"In italiano l'aggettivo concorda in genere (maschile/femminile) e numero (singolare/plurale) con il nome. Gli aggettivi in -o hanno quattro forme (rosso, rossa, rossi, rosse); quelli in -e hanno due forme (grande, grandi). Di solito l'aggettivo va dopo il nome, ma buono, bello e grande spesso vanno prima e cambiano forma.","ru":"В итальянском прилагательное согласуется с существительным в роде (мужской/женский) и числе (единственное/множественное). Прилагательные на -o имеют четыре формы (rosso, rossa, rossi, rosse); на -e — две формы (grande, grandi). Обычно прилагательное стоит после существительного, но buono, bello и grande часто идут перед ним и меняют форму.","de":"Im Italienischen richtet sich das Adjektiv in Geschlecht (männlich/weiblich) und Zahl (Singular/Plural) nach dem Nomen. Adjektive auf -o haben vier Formen (rosso, rossa, rossi, rosse); die auf -e haben zwei Formen (grande, grandi). Normalerweise steht das Adjektiv nach dem Nomen, aber buono, bello und grande stehen oft davor und ändern ihre Form.","en":"In Italian the adjective agrees in gender (masculine/feminine) and number (singular/plural) with the noun. Adjectives ending in -o have four forms (rosso, rossa, rossi, rosse); those ending in -e have two forms (grande, grandi). The adjective usually follows the noun, but buono, bello and grande often go before it and change their form.","uk":"В італійській прикметник узгоджується з іменником у роді (чоловічий/жіночий) і числі (однина/множина). Прикметники на -o мають чотири форми (rosso, rossa, rossi, rosse); на -e — дві форми (grande, grandi). Зазвичай прикметник стоїть після іменника, але buono, bello і grande часто йдуть перед ним і змінюють форму.","fa":"در ایتالیایی صفت از نظر جنس (مذکر/مؤنث) و شمار (مفرد/جمع) با اسم مطابقت می‌کند. صفت‌های پایان‌یافته به ‎-o‎ چهار شکل دارند (rosso, rossa, rossi, rosse)؛ آن‌هایی که به ‎-e‎ ختم می‌شوند دو شکل دارند (grande, grandi). معمولاً صفت بعد از اسم می‌آید، اما buono، bello و grande اغلب پیش از اسم می‌آیند و شکلشان تغییر می‌کند."},"tables":[{"caption":{"it":"Accordo dell'aggettivo","ru":"Согласование прилагательного","de":"Angleichung des Adjektivs","en":"Adjective agreement","uk":"Узгодження прикметника","fa":"مطابقت صفت"},"labelHeader":{"it":"Tipo","ru":"Тип","de":"Typ","en":"Type","uk":"Тип","fa":"نوع"},"columns":[{"it":"Maschile sing.","ru":"Муж. ед.","de":"Mask. Sing.","en":"Masc. sing.","uk":"Чол. одн.","fa":"مذکر مفرد"},{"it":"Femminile sing.","ru":"Жен. ед.","de":"Fem. Sing.","en":"Fem. sing.","uk":"Жін. одн.","fa":"مؤنث مفرد"},{"it":"Maschile plur.","ru":"Муж. мн.","de":"Mask. Pl.","en":"Masc. plur.","uk":"Чол. мн.","fa":"مذکر جمع"},{"it":"Femminile plur.","ru":"Жен. мн.","de":"Fem. Pl.","en":"Fem. plur.","uk":"Жін. мн.","fa":"مؤنث جمع"}],"rows":[{"label":{"it":"in -o (4 forme)","ru":"на -o (4 формы)","de":"auf -o (4 Formen)","en":"in -o (4 forms)","uk":"на -o (4 форми)","fa":"با ‎-o‎ (۴ شکل)"},"cells":["rosso","rossa","rossi","rosse"]},{"label":{"it":"in -e (2 forme)","ru":"на -e (2 формы)","de":"auf -e (2 Formen)","en":"in -e (2 forms)","uk":"на -e (2 форми)","fa":"با ‎-e‎ (۲ شکل)"},"cells":["grande","grande","grandi","grandi"]},{"label":{"it":"in -e (2 forme)","ru":"на -e (2 формы)","de":"auf -e (2 Formen)","en":"in -e (2 forms)","uk":"на -e (2 форми)","fa":"با ‎-e‎ (۲ شکل)"},"cells":["felice","felice","felici","felici"]}]},{"caption":{"it":"Aggettivi speciali: buono, bello, grande","ru":"Особые прилагательные: buono, bello, grande","de":"Besondere Adjektive: buono, bello, grande","en":"Special adjectives: buono, bello, grande","uk":"Особливі прикметники: buono, bello, grande","fa":"صفت‌های خاص: buono، bello، grande"},"labelHeader":{"it":"Aggettivo","ru":"Прилагательное","de":"Adjektiv","en":"Adjective","uk":"Прикметник","fa":"صفت"},"columns":[{"it":"Prima del nome","ru":"Перед существительным","de":"Vor dem Nomen","en":"Before the noun","uk":"Перед іменником","fa":"پیش از اسم"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"buono (buono/a)","ru":"buono (хороший)","de":"buono (gut)","en":"buono (good)","uk":"buono (хороший)","fa":"buono (خوب)"},"cells":["buon, buono, buona, buon'","un buon amico, una buona idea"]},{"label":{"it":"bello (bello/a)","ru":"bello (красивый)","de":"bello (schön)","en":"bello (beautiful)","uk":"bello (гарний)","fa":"bello (زیبا)"},"cells":["bel, bello, bell', bella","un bel giorno, un bello specchio"]},{"label":{"it":"grande (grande)","ru":"grande (большой)","de":"grande (groß)","en":"grande (big)","uk":"grande (великий)","fa":"grande (بزرگ)"},"cells":["gran, grande, grand'","una gran festa, un grande uomo"]}]}],"examples":[{"it":"La casa nuova è molto grande.","ru":"Новый дом очень большой.","de":"Das neue Haus ist sehr groß.","en":"The new house is very big.","uk":"Новий дім дуже великий.","fa":"خانهٔ نو خیلی بزرگ است."},{"it":"Ho comprato due macchine rosse.","ru":"Я купил две красные машины.","de":"Ich habe zwei rote Autos gekauft.","en":"I bought two red cars.","uk":"Я купив два червоні автомобілі.","fa":"دو ماشین قرمز خریدم."},{"it":"È un buon ristorante con un bel giardino.","ru":"Это хороший ресторан с красивым садом.","de":"Es ist ein gutes Restaurant mit einem schönen Garten.","en":"It's a good restaurant with a nice garden.","uk":"Це хороший ресторан з гарним садом.","fa":"این یک رستوران خوب با باغی زیبا است."}],"hints":{"ru":"Прилагательные на -o меняют окончание по роду и числу (-o/-a/-i/-e); на -e — только по числу (-e/-i). Buono перед существительным ведёт себя как артикль un: un buon amico. Bello перед существительным следует за формами определённого артикля: bel, bello, bella, bei, begli, belle.","de":"Adjektive auf -o ändern die Endung nach Geschlecht und Zahl (-o/-a/-i/-e); die auf -e nur nach Zahl (-e/-i). Buono verhält sich vor dem Nomen wie der Artikel un: un buon amico. Bello folgt vor dem Nomen den Formen des bestimmten Artikels: bel, bello, bella, bei, begli, belle.","en":"Adjectives in -o change ending by gender and number (-o/-a/-i/-e); those in -e change only by number (-e/-i). Before a noun, buono behaves like the article un: un buon amico. Before a noun, bello follows the definite-article forms: bel, bello, bella, bei, begli, belle.","uk":"Прикметники на -o змінюють закінчення за родом і числом (-o/-a/-i/-e); на -e — лише за числом (-e/-i). Перед іменником buono поводиться як артикль un: un buon amico. Перед іменником bello слідує формам означеного артикля: bel, bello, bella, bei, begli, belle.","fa":"صفت‌های ‎-o‎ پایانه را بر پایهٔ جنس و شمار تغییر می‌دهند (‎-o/-a/-i/-e‎)؛ صفت‌های ‎-e‎ فقط بر پایهٔ شمار (‎-e/-i‎). buono پیش از اسم مانند حرف تعریف un رفتار می‌کند: un buon amico. bello پیش از اسم از شکل‌های حرف تعریف معرفه پیروی می‌کند: bel, bello, bella, bei, begli, belle."}},
{"id":"negazione-interrogazione","icon":"❓","level":"A1","title":{"it":"Negazione e interrogazione","ru":"Отрицание и вопрос","de":"Verneinung und Frage","en":"Negation and questions","uk":"Заперечення та питання","fa":"نفی و پرسش"},"intro":{"it":"Per negare si mette non davanti al verbo: non capisco. Con mai, niente/nulla, nessuno si usa la doppia negazione: non... mai, non... niente, non... nessuno. Le domande sì/no si formano con la sola intonazione (l'ordine delle parole non cambia): Parli italiano? Per le domande aperte si usano le parole interrogative chi, che/cosa, dove, quando, come, quanto, perché.","ru":"Для отрицания перед глаголом ставится non: non capisco. С mai, niente/nulla, nessuno используется двойное отрицание: non... mai, non... niente, non... nessuno. Вопросы «да/нет» образуются только интонацией (порядок слов не меняется): Parli italiano? Для открытых вопросов используются вопросительные слова chi, che/cosa, dove, quando, come, quanto, perché.","de":"Zum Verneinen steht non vor dem Verb: non capisco. Mit mai, niente/nulla, nessuno benutzt man die doppelte Verneinung: non... mai, non... niente, non... nessuno. Ja/Nein-Fragen bildet man nur mit der Intonation (die Wortstellung ändert sich nicht): Parli italiano? Für offene Fragen benutzt man die Fragewörter chi, che/cosa, dove, quando, come, quanto, perché.","en":"To negate, put non before the verb: non capisco. With mai, niente/nulla, nessuno you use a double negative: non... mai, non... niente, non... nessuno. Yes/no questions are formed by intonation alone (word order does not change): Parli italiano? For open questions use the question words chi, che/cosa, dove, quando, come, quanto, perché.","uk":"Щоб заперечити, перед дієсловом ставлять non: non capisco. З mai, niente/nulla, nessuno вживають подвійне заперечення: non... mai, non... niente, non... nessuno. Питання «так/ні» утворюються лише інтонацією (порядок слів не змінюється): Parli italiano? Для відкритих питань уживають питальні слова chi, che/cosa, dove, quando, come, quanto, perché.","fa":"برای منفی کردن، non را پیش از فعل می‌گذارند: non capisco. با mai، niente/nulla، nessuno از نفی دوگانه استفاده می‌شود: non... mai، non... niente، non... nessuno. پرسش‌های بله/خیر تنها با آهنگ صدا ساخته می‌شوند (ترتیب کلمات تغییر نمی‌کند): Parli italiano? برای پرسش‌های باز از کلمات پرسشی chi، che/cosa، dove، quando، come، quanto، perché استفاده کنید."},"tables":[{"caption":{"it":"La negazione doppia","ru":"Двойное отрицание","de":"Die doppelte Verneinung","en":"The double negative","uk":"Подвійне заперечення","fa":"نفی دوگانه"},"labelHeader":{"it":"Significato","ru":"Значение","de":"Bedeutung","en":"Meaning","uk":"Значення","fa":"معنی"},"columns":[{"it":"Struttura","ru":"Структура","de":"Struktur","en":"Structure","uk":"Структура","fa":"ساختار"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"semplice","ru":"не (простое)","de":"nicht (einfach)","en":"not (simple)","uk":"не (просте)","fa":"نه (ساده)"},"cells":["non + verbo","Non parlo tedesco."]},{"label":{"it":"mai","ru":"никогда","de":"nie","en":"never","uk":"ніколи","fa":"هرگز"},"cells":["non... mai","Non fumo mai."]},{"label":{"it":"niente/nulla","ru":"ничего","de":"nichts","en":"nothing","uk":"нічого","fa":"هیچ‌چیز"},"cells":["non... niente","Non capisco niente."]},{"label":{"it":"nessuno","ru":"никто/никакой","de":"niemand/kein","en":"nobody/no one","uk":"ніхто/жоден","fa":"هیچ‌کس"},"cells":["non... nessuno","Non conosco nessuno."]}]},{"caption":{"it":"Le parole interrogative","ru":"Вопросительные слова","de":"Die Fragewörter","en":"Question words","uk":"Питальні слова","fa":"کلمات پرسشی"},"labelHeader":{"it":"Significato","ru":"Значение","de":"Bedeutung","en":"Meaning","uk":"Значення","fa":"معنی"},"columns":[{"it":"Parola","ru":"Слово","de":"Wort","en":"Word","uk":"Слово","fa":"کلمه"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"chi","ru":"кто","de":"wer","en":"who","uk":"хто","fa":"چه کسی"},"cells":["chi","Chi è?"]},{"label":{"it":"che cosa","ru":"что","de":"was","en":"what","uk":"що","fa":"چه / چه چیزی"},"cells":["che / cosa","Che cosa fai?"]},{"label":{"it":"dove","ru":"где","de":"wo","en":"where","uk":"де","fa":"کجا"},"cells":["dove","Dove abiti?"]},{"label":{"it":"quando","ru":"когда","de":"wann","en":"when","uk":"коли","fa":"کِی / چه وقت"},"cells":["quando","Quando parti?"]},{"label":{"it":"come","ru":"как","de":"wie","en":"how","uk":"як","fa":"چطور"},"cells":["come","Come stai?"]},{"label":{"it":"quanto","ru":"сколько","de":"wie viel","en":"how much","uk":"скільки","fa":"چقدر"},"cells":["quanto","Quanto costa?"]},{"label":{"it":"perché","ru":"почему","de":"warum","en":"why","uk":"чому","fa":"چرا"},"cells":["perché","Perché studi l'italiano?"]}]}],"examples":[{"it":"Non ho mai visto questo film.","ru":"Я никогда не видел этот фильм.","de":"Ich habe diesen Film nie gesehen.","en":"I have never seen this film.","uk":"Я ніколи не бачив цей фільм.","fa":"من هرگز این فیلم را ندیده‌ام."},{"it":"Dove vai in vacanza quest'anno?","ru":"Куда ты едешь в отпуск в этом году?","de":"Wohin fährst du dieses Jahr in den Urlaub?","en":"Where are you going on holiday this year?","uk":"Куди ти їдеш у відпустку цього року?","fa":"امسال برای تعطیلات کجا می‌روی؟"},{"it":"Parli inglese? — No, non parlo inglese.","ru":"Ты говоришь по-английски? — Нет, я не говорю по-английски.","de":"Sprichst du Englisch? — Nein, ich spreche kein Englisch.","en":"Do you speak English? — No, I don't speak English.","uk":"Ти розмовляєш англійською? — Ні, я не розмовляю англійською.","fa":"انگلیسی صحبت می‌کنی؟ — نه، انگلیسی صحبت نمی‌کنم."}],"hints":{"ru":"Non всегда стоит непосредственно перед глаголом. При двойном отрицании non остаётся перед глаголом, а mai/niente/nessuno — после: non dico niente. Если nessuno/niente стоит перед глаголом как подлежащее, non опускается: Nessuno risponde. Вопросы «да/нет» отличаются только восходящей интонацией; вопросительные слова обычно стоят в начале.","de":"Non steht immer direkt vor dem Verb. Bei der doppelten Verneinung bleibt non vor dem Verb und mai/niente/nessuno stehen danach: non dico niente. Steht nessuno/niente als Subjekt vor dem Verb, fällt non weg: Nessuno risponde. Ja/Nein-Fragen unterscheiden sich nur durch die steigende Intonation; Fragewörter stehen meist am Anfang.","en":"Non always comes right before the verb. In the double negative, non stays before the verb and mai/niente/nessuno come after: non dico niente. When nessuno/niente is the subject before the verb, non is dropped: Nessuno risponde. Yes/no questions differ only by rising intonation; question words normally go first.","uk":"Non завжди стоїть безпосередньо перед дієсловом. У подвійному запереченні non залишається перед дієсловом, а mai/niente/nessuno — після: non dico niente. Коли nessuno/niente є підметом перед дієсловом, non випускається: Nessuno risponde. Питання «так/ні» відрізняються лише висхідною інтонацією; питальні слова зазвичай стоять на початку.","fa":"non همیشه درست پیش از فعل می‌آید. در نفی دوگانه، non پیش از فعل می‌ماند و mai/niente/nessuno پس از آن می‌آیند: non dico niente. وقتی nessuno/niente نهاد و پیش از فعل باشد، non حذف می‌شود: Nessuno risponde. پرسش‌های بله/خیر فقط با آهنگ بالارونده فرق دارند؛ کلمات پرسشی معمولاً در آغاز می‌آیند."}},
{"id":"dimostrativi-cesono","icon":"📍","level":"A1","title":{"it":"C'è / ci sono, questo / quello, ecco","ru":"C'è / ci sono, questo / quello, ecco","de":"C'è / ci sono, questo / quello, ecco","en":"C'è / ci sono, questo / quello, ecco","uk":"C'è / ci sono, questo / quello, ecco","fa":"C'è / ci sono، questo / quello، ecco"},"intro":{"it":"Per dire che qualcosa esiste o si trova in un luogo si usa c'è (singolare) e ci sono (plurale): C'è un problema. Ci sono due libri. Per indicare le cose si usano i dimostrativi questo (vicino: questo, questa, questi, queste) e quello (lontano). Quello davanti al nome cambia come l'articolo determinativo (quel, quello, quell', quella). Ecco significa \"ecco qua/là\" e presenta qualcosa: Ecco il treno!","ru":"Чтобы сказать, что что-то существует или находится в каком-то месте, используют c'è (единственное число) и ci sono (множественное): C'è un problema. Ci sono due libri. Для указания на предметы используют указательные questo (близко: questo, questa, questi, queste) и quello (далеко). Quello перед существительным изменяется как определённый артикль (quel, quello, quell', quella). Ecco значит «вот» и представляет что-то: Ecco il treno!","de":"Um zu sagen, dass etwas existiert oder sich an einem Ort befindet, benutzt man c'è (Singular) und ci sono (Plural): C'è un problema. Ci sono due libri. Zum Zeigen verwendet man die Demonstrativa questo (nah: questo, questa, questi, queste) und quello (fern). Quello ändert sich vor dem Nomen wie der bestimmte Artikel (quel, quello, quell', quella). Ecco bedeutet \"da ist/sind\" und stellt etwas vor: Ecco il treno!","en":"To say that something exists or is in a place, use c'è (singular) and ci sono (plural): C'è un problema. Ci sono due libri. To point at things use the demonstratives questo (near: questo, questa, questi, queste) and quello (far). Before a noun, quello changes like the definite article (quel, quello, quell', quella). Ecco means \"here is/there is\" and presents something: Ecco il treno!","uk":"Щоб сказати, що щось існує або знаходиться в якомусь місці, вживають c'è (однина) і ci sono (множина): C'è un problema. Ci sono due libri. Для вказівки на предмети вживають вказівні questo (близько: questo, questa, questi, queste) і quello (далеко). Quello перед іменником змінюється як означений артикль (quel, quello, quell', quella). Ecco означає «ось» і представляє щось: Ecco il treno!","fa":"برای گفتن اینکه چیزی وجود دارد یا در جایی هست از c'è (مفرد) و ci sono (جمع) استفاده کنید: C'è un problema. Ci sono due libri. برای اشاره به چیزها از اشاره‌گرهای questo (نزدیک: questo, questa, questi, queste) و quello (دور) استفاده می‌شود. quello پیش از اسم مانند حرف تعریف معرفه تغییر می‌کند (quel, quello, quell', quella). ecco یعنی «این است/آنجاست» و چیزی را معرفی می‌کند: Ecco il treno!"},"tables":[{"caption":{"it":"C'è e ci sono","ru":"C'è и ci sono","de":"C'è und ci sono","en":"C'è and ci sono","uk":"C'è та ci sono","fa":"C'è و ci sono"},"labelHeader":{"it":"Numero","ru":"Число","de":"Zahl","en":"Number","uk":"Число","fa":"شمار"},"columns":[{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"شکل"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"Singolare","ru":"Ед. число","de":"Singular","en":"Singular","uk":"Однина","fa":"مفرد"},"cells":["c'è","C'è un gatto in giardino."]},{"label":{"it":"Plurale","ru":"Мн. число","de":"Plural","en":"Plural","uk":"Множина","fa":"جمع"},"cells":["ci sono","Ci sono molte persone."]},{"label":{"it":"Presentare","ru":"Указание «вот»","de":"Präsentieren","en":"Presenting","uk":"Вказівка «ось»","fa":"معرفی کردن"},"cells":["ecco","Ecco la tua chiave!"]}]},{"caption":{"it":"Questo e quello","ru":"Questo и quello","de":"Questo und quello","en":"Questo and quello","uk":"Questo та quello","fa":"Questo و quello"},"labelHeader":{"it":"Genere/numero","ru":"Род/число","de":"Genus/Zahl","en":"Gender/number","uk":"Рід/число","fa":"جنس/شمار"},"columns":[{"it":"questo (vicino)","ru":"questo (близко)","de":"questo (nah)","en":"questo (near)","uk":"questo (близько)","fa":"questo (نزدیک)"},{"it":"quello (lontano)","ru":"quello (далеко)","de":"quello (fern)","en":"quello (far)","uk":"quello (далеко)","fa":"quello (دور)"}],"rows":[{"label":{"it":"Masch. sing.","ru":"Муж. ед.","de":"Mask. Sing.","en":"Masc. sing.","uk":"Чол. одн.","fa":"مذکر مفرد"},"cells":["questo (quest')","quel / quello / quell'"]},{"label":{"it":"Femm. sing.","ru":"Жен. ед.","de":"Fem. Sing.","en":"Fem. sing.","uk":"Жін. одн.","fa":"مؤنث مفرد"},"cells":["questa (quest')","quella (quell')"]},{"label":{"it":"Masch. plur.","ru":"Муж. мн.","de":"Mask. Pl.","en":"Masc. plur.","uk":"Чол. мн.","fa":"مذکر جمع"},"cells":["questi","quei / quegli"]},{"label":{"it":"Femm. plur.","ru":"Жен. мн.","de":"Fem. Pl.","en":"Fem. plur.","uk":"Жін. мн.","fa":"مؤنث جمع"},"cells":["queste","quelle"]}]}],"examples":[{"it":"C'è un ristorante qui vicino? — Sì, ci sono due ristoranti.","ru":"Здесь поблизости есть ресторан? — Да, есть два ресторана.","de":"Gibt es hier in der Nähe ein Restaurant? — Ja, es gibt zwei Restaurants.","en":"Is there a restaurant nearby? — Yes, there are two restaurants.","uk":"Тут поблизу є ресторан? — Так, є два ресторани.","fa":"این نزدیکی رستورانی هست؟ — بله، دو رستوران هست."},{"it":"Questo libro è mio, quel libro è tuo.","ru":"Эта книга моя, та книга твоя.","de":"Dieses Buch ist meins, jenes Buch ist deins.","en":"This book is mine, that book is yours.","uk":"Ця книга моя, та книга твоя.","fa":"این کتاب مال من است، آن کتاب مال توست."},{"it":"Ecco i tuoi occhiali, erano sul tavolo!","ru":"Вот твои очки, они были на столе!","de":"Da sind deine Brille, sie war auf dem Tisch!","en":"Here are your glasses, they were on the table!","uk":"Ось твої окуляри, вони були на столі!","fa":"این هم عینکت، روی میز بود!"}],"hints":{"ru":"C'è / ci sono сообщают о наличии; согласуйте с тем, что идёт после (единственное или множественное). Questo указывает на близкое, quello — на далёкое. Quello перед существительным ведёт себя как определённый артикль: quel treno, quello studente, quell'amico, quella casa, quei libri, quegli zaini, quelle ragazze. Ecco неизменяемо и часто присоединяет местоимение: eccomi, eccolo.","de":"C'è / ci sono geben das Vorhandensein an; richten Sie sie nach dem, was folgt (Singular oder Plural). Questo zeigt Nahes, quello Fernes. Quello vor dem Nomen verhält sich wie der bestimmte Artikel: quel treno, quello studente, quell'amico, quella casa, quei libri, quegli zaini, quelle ragazze. Ecco ist unveränderlich und nimmt oft ein Pronomen an: eccomi, eccolo.","en":"C'è / ci sono state existence; agree them with what follows (singular or plural). Questo points to something near, quello to something far. Before a noun, quello behaves like the definite article: quel treno, quello studente, quell'amico, quella casa, quei libri, quegli zaini, quelle ragazze. Ecco is invariable and often takes a pronoun: eccomi, eccolo.","uk":"C'è / ci sono повідомляють про наявність; узгоджуйте з тим, що йде далі (однина чи множина). Questo вказує на близьке, quello — на далеке. Quello перед іменником поводиться як означений артикль: quel treno, quello studente, quell'amico, quella casa, quei libri, quegli zaini, quelle ragazze. Ecco незмінне й часто приєднує займенник: eccomi, eccolo.","fa":"C'è / ci sono وجود چیزی را بیان می‌کنند؛ آن‌ها را با آنچه پس از آن می‌آید (مفرد یا جمع) مطابقت دهید. questo به چیز نزدیک و quello به چیز دور اشاره می‌کند. quello پیش از اسم مانند حرف تعریف معرفه رفتار می‌کند: quel treno, quello studente, quell'amico, quella casa, quei libri, quegli zaini, quelle ragazze. ecco تغییرناپذیر است و اغلب ضمیر می‌گیرد: eccomi, eccolo."}},
{"id":"preposizioni","icon":"🧭","level":"A1","title":{"it":"Le preposizioni e le preposizioni articolate","ru":"Предлоги и слитные предлоги с артиклем","de":"Präpositionen und Präpositionen mit Artikel","en":"Prepositions and prepositions with the article","uk":"Прийменники та злиті прийменники з артиклем","fa":"حروف اضافه و حروف اضافهٔ ترکیب‌شده با حرف تعریف"},"intro":{"it":"Le preposizioni semplici sono di, a, da, in, con, su, per, tra/fra. Indicano possesso e origine (di), luogo e tempo (a, in), moto da luogo o agente (da), mezzo/compagnia (con), posizione (su), scopo (per), relazione (tra/fra). Quando di, a, da, in, su sono seguite dall'articolo determinativo, si fondono con esso: di + il = del, a + il = al, da + il = dal, in + il = nel, su + il = sul. Con e per di solito non si fondono.","ru":"Простые предлоги: di, a, da, in, con, su, per, tra/fra. Они выражают принадлежность и происхождение (di), место и время (a, in), движение из места или действующее лицо (da), средство/компанию (con), положение (su), цель (per), отношение (tra/fra). Когда di, a, da, in, su стоят перед определённым артиклем, они сливаются с ним: di + il = del, a + il = al, da + il = dal, in + il = nel, su + il = sul. Con и per обычно не сливаются.","de":"Die einfachen Präpositionen sind di, a, da, in, con, su, per, tra/fra. Sie geben Besitz und Herkunft (di), Ort und Zeit (a, in), Bewegung von einem Ort oder den Urheber (da), Mittel/Begleitung (con), Position (su), Zweck (per), Beziehung (tra/fra) an. Wenn di, a, da, in, su auf den bestimmten Artikel folgen, verschmelzen sie mit ihm: di + il = del, a + il = al, da + il = dal, in + il = nel, su + il = sul. Con und per verschmelzen meist nicht.","en":"The simple prepositions are di, a, da, in, con, su, per, tra/fra. They express possession and origin (di), place and time (a, in), movement from a place or the agent (da), means/company (con), position (su), purpose (per), relation (tra/fra). When di, a, da, in, su are followed by the definite article, they merge with it: di + il = del, a + il = al, da + il = dal, in + il = nel, su + il = sul. Con and per usually do not merge.","uk":"Прості прийменники: di, a, da, in, con, su, per, tra/fra. Вони виражають належність і походження (di), місце й час (a, in), рух із місця або діяча (da), засіб/супровід (con), розташування (su), мету (per), відношення (tra/fra). Коли di, a, da, in, su стоять перед означеним артиклем, вони зливаються з ним: di + il = del, a + il = al, da + il = dal, in + il = nel, su + il = sul. Con і per зазвичай не зливаються.","fa":"حروف اضافهٔ ساده عبارت‌اند از di، a، da، in، con، su، per، tra/fra. آن‌ها مالکیت و منشأ (di)، مکان و زمان (a، in)، حرکت از مکان یا کنشگر (da)، وسیله/همراهی (con)، جایگاه (su)، هدف (per)، نسبت (tra/fra) را بیان می‌کنند. وقتی di، a، da، in، su پیش از حرف تعریف معرفه بیایند با آن ترکیب می‌شوند: di + il = del، a + il = al، da + il = dal، in + il = nel، su + il = sul. con و per معمولاً ترکیب نمی‌شوند."},"tables":[{"caption":{"it":"Le preposizioni semplici","ru":"Простые предлоги","de":"Die einfachen Präpositionen","en":"The simple prepositions","uk":"Прості прийменники","fa":"حروف اضافهٔ ساده"},"labelHeader":{"it":"Uso","ru":"Употребление","de":"Gebrauch","en":"Use","uk":"Вживання","fa":"کاربرد"},"columns":[{"it":"Preposizione","ru":"Предлог","de":"Präposition","en":"Preposition","uk":"Прийменник","fa":"حرف اضافه"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"possesso, origine","ru":"принадлежность, происхождение","de":"Besitz, Herkunft","en":"possession, origin","uk":"належність, походження","fa":"مالکیت، منشأ"},"cells":["di","il libro di Marco"]},{"label":{"it":"luogo, direzione","ru":"место, направление","de":"Ort, Richtung","en":"place, direction","uk":"місце, напрямок","fa":"مکان، جهت"},"cells":["a","Vado a Roma."]},{"label":{"it":"provenienza, agente","ru":"происхождение, действующее лицо","de":"Herkunft, Urheber","en":"origin, agent","uk":"походження, діяч","fa":"منشأ، کنشگر"},"cells":["da","Vengo da Milano."]},{"label":{"it":"luogo (dentro)","ru":"место (внутри)","de":"Ort (in)","en":"place (in)","uk":"місце (всередині)","fa":"مکان (درون)"},"cells":["in","Abito in Italia."]},{"label":{"it":"compagnia, mezzo","ru":"сопровождение, средство","de":"Begleitung, Mittel","en":"company, means","uk":"супровід, засіб","fa":"همراهی، وسیله"},"cells":["con","Esco con Anna."]},{"label":{"it":"posizione, argomento","ru":"положение, тема","de":"Position, Thema","en":"position, about","uk":"розташування, тема","fa":"جایگاه، موضوع"},"cells":["su","Un libro su Roma."]},{"label":{"it":"scopo, destinazione","ru":"цель, назначение","de":"Zweck, Ziel","en":"purpose, destination","uk":"мета, призначення","fa":"هدف، مقصد"},"cells":["per","Un regalo per te."]},{"label":{"it":"relazione, tempo","ru":"отношение, время","de":"Beziehung, Zeit","en":"relation, time","uk":"відношення, час","fa":"نسبت، زمان"},"cells":["tra / fra","Tra due ore."]}]},{"caption":{"it":"Le preposizioni articolate","ru":"Слитные предлоги с артиклем","de":"Präpositionen mit Artikel","en":"Prepositions with the article","uk":"Злиті прийменники з артиклем","fa":"حروف اضافهٔ ترکیب‌شده"},"labelHeader":{"it":"Prep. + articolo","ru":"Предлог + артикль","de":"Präp. + Artikel","en":"Prep. + article","uk":"Прийм. + артикль","fa":"حرف اضافه + حرف تعریف"},"columns":[{"it":"il","ru":"il","de":"il","en":"il","uk":"il","fa":"il"},{"it":"lo / l'","ru":"lo / l'","de":"lo / l'","en":"lo / l'","uk":"lo / l'","fa":"lo / l'"},{"it":"la","ru":"la","de":"la","en":"la","uk":"la","fa":"la"},{"it":"i","ru":"i","de":"i","en":"i","uk":"i","fa":"i"},{"it":"le","ru":"le","de":"le","en":"le","uk":"le","fa":"le"}],"rows":[{"label":{"it":"di","ru":"di","de":"di","en":"di","uk":"di","fa":"di"},"cells":["del","dello / dell'","della","dei","delle"]},{"label":{"it":"a","ru":"a","de":"a","en":"a","uk":"a","fa":"a"},"cells":["al","allo / all'","alla","ai","alle"]},{"label":{"it":"da","ru":"da","de":"da","en":"da","uk":"da","fa":"da"},"cells":["dal","dallo / dall'","dalla","dai","dalle"]},{"label":{"it":"in","ru":"in","de":"in","en":"in","uk":"in","fa":"in"},"cells":["nel","nello / nell'","nella","nei","nelle"]},{"label":{"it":"su","ru":"su","de":"su","en":"su","uk":"su","fa":"su"},"cells":["sul","sullo / sull'","sulla","sui","sulle"]}]}],"examples":[{"it":"Il libro è sul tavolo, vicino alla finestra.","ru":"Книга на столе, рядом с окном.","de":"Das Buch liegt auf dem Tisch, neben dem Fenster.","en":"The book is on the table, next to the window.","uk":"Книга на столі, біля вікна.","fa":"کتاب روی میز است، کنار پنجره."},{"it":"Torno dal medico e poi vado al mercato.","ru":"Я возвращаюсь от врача, а потом иду на рынок.","de":"Ich komme vom Arzt zurück und gehe dann zum Markt.","en":"I'm coming back from the doctor and then going to the market.","uk":"Я повертаюся від лікаря, а потім іду на ринок.","fa":"از پزشک برمی‌گردم و بعد به بازار می‌روم."},{"it":"La casa dei miei amici è nel centro della città.","ru":"Дом моих друзей находится в центре города.","de":"Das Haus meiner Freunde liegt im Zentrum der Stadt.","en":"My friends' house is in the city centre.","uk":"Дім моїх друзів у центрі міста.","fa":"خانهٔ دوستانم در مرکز شهر است."}],"hints":{"ru":"Простые предлоги di, a, da, in, su ОБЯЗАТЕЛЬНО сливаются с определённым артиклем: su la sedia неверно — надо sulla sedia. Con и per обычно остаются раздельными (con il, per il). Не путайте da (движение «от», агент, «у кого-то») с di (принадлежность, «из откуда родом»). Для стран используйте in (in Italia), для городов — a (a Roma).","de":"Die einfachen Präpositionen di, a, da, in, su verschmelzen ZWINGEND mit dem bestimmten Artikel: su la sedia ist falsch — es muss sulla sedia heißen. Con und per bleiben meist getrennt (con il, per il). Verwechseln Sie da (Bewegung „von“, Urheber, „bei jemandem“) nicht mit di (Besitz, Herkunft). Für Länder benutzt man in (in Italia), für Städte a (a Roma).","en":"The simple prepositions di, a, da, in, su MUST merge with the definite article: su la sedia is wrong — it must be sulla sedia. Con and per usually stay separate (con il, per il). Don't confuse da (movement 'from', agent, 'at someone's place') with di (possession, where you are from). Use in for countries (in Italia) and a for cities (a Roma).","uk":"Прості прийменники di, a, da, in, su ОБОВ'ЯЗКОВО зливаються з означеним артиклем: su la sedia неправильно — треба sulla sedia. Con і per зазвичай залишаються окремими (con il, per il). Не плутайте da (рух «від», діяч, «у когось») з di (належність, звідки родом). Для країн уживайте in (in Italia), для міст — a (a Roma).","fa":"حروف اضافهٔ سادهٔ di، a، da، in، su حتماً با حرف تعریف معرفه ترکیب می‌شوند: su la sedia نادرست است — باید sulla sedia باشد. con و per معمولاً جدا می‌مانند (con il، per il). da (حرکت «از»، کنشگر، «نزد کسی») را با di (مالکیت، اهل کجا بودن) اشتباه نگیرید. برای کشورها in (in Italia) و برای شهرها a (a Roma) به کار می‌رود."}},
{"id":"passato-prossimo","icon":"📅","level":"A2","title":{"it":"Passato prossimo","ru":"Passato prossimo (прошедшее составное)","de":"Passato prossimo (Perfekt)","en":"Passato prossimo (present perfect)","uk":"Passato prossimo (минулий складений)","fa":"ماضی نقلی (passato prossimo)"},"intro":{"it":"Il passato prossimo esprime azioni concluse nel passato. Si forma con l'ausiliare avere o essere al presente più il participio passato. Con essere il participio concorda in genere e numero con il soggetto.","ru":"Passato prossimo выражает завершённые действия в прошлом. Образуется вспомогательным глаголом avere или essere в настоящем времени плюс причастие прошедшего времени. С essere причастие согласуется в роде и числе с подлежащим.","de":"Das Passato prossimo drückt abgeschlossene Handlungen in der Vergangenheit aus. Es wird mit dem Hilfsverb avere oder essere im Präsens plus dem Partizip Perfekt gebildet. Mit essere richtet sich das Partizip in Geschlecht und Zahl nach dem Subjekt.","en":"The passato prossimo expresses completed actions in the past. It is formed with the auxiliary avere or essere in the present tense plus the past participle. With essere the participle agrees in gender and number with the subject.","uk":"Passato prossimo виражає завершені дії в минулому. Утворюється допоміжним дієсловом avere або essere в теперішньому часі плюс дієприкметник минулого часу. З essere дієприкметник узгоджується в роді та числі з підметом.","fa":"ماضی نقلی برای بیان کارهای پایان‌یافته در گذشته به کار می‌رود. با فعل کمکی avere یا essere در زمان حال به‌علاوهٔ اسم مفعول ساخته می‌شود. با essere اسم مفعول از نظر جنس و شمار با فاعل مطابقت می‌کند."},"tables":[{"caption":{"it":"avere + participio (parlare)","ru":"avere + причастие (parlare)","de":"avere + Partizip (parlare)","en":"avere + participle (parlare)","uk":"avere + дієприкметник (parlare)","fa":"avere + اسم مفعول (parlare)"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"صورت"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["ho parlato"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["hai parlato"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["ha parlato"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["abbiamo parlato"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["avete parlato"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["hanno parlato"]}]},{"caption":{"it":"essere + participio (andare, accordo)","ru":"essere + причастие (andare, согласование)","de":"essere + Partizip (andare, Angleichung)","en":"essere + participle (andare, agreement)","uk":"essere + дієприкметник (andare, узгодження)","fa":"essere + اسم مفعول (andare، مطابقت)"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Maschile","ru":"Мужской род","de":"Maskulin","en":"Masculine","uk":"Чоловічий рід","fa":"مذکر"},{"it":"Femminile","ru":"Женский род","de":"Feminin","en":"Feminine","uk":"Жіночий рід","fa":"مؤنث"}],"rows":[{"label":{"it":"io/tu/lui/lei","ru":"ед. число","de":"Singular","en":"singular","uk":"однина","fa":"مفرد"},"cells":["sono andato","sono andata"]},{"label":{"it":"noi/voi/loro","ru":"мн. число","de":"Plural","en":"plural","uk":"множина","fa":"جمع"},"cells":["siamo andati","siamo andate"]}]}],"examples":[{"it":"Ho mangiato una pizza ieri sera.","ru":"Вчера вечером я съел пиццу.","de":"Ich habe gestern Abend eine Pizza gegessen.","en":"I ate a pizza yesterday evening.","uk":"Учора ввечері я з'їв піцу.","fa":"دیشب یک پیتزا خوردم."},{"it":"Maria è partita per Roma.","ru":"Мария уехала в Рим.","de":"Maria ist nach Rom abgereist.","en":"Maria left for Rome.","uk":"Марія поїхала до Рима.","fa":"ماریا به رم رفت."},{"it":"I ragazzi sono arrivati in ritardo.","ru":"Ребята приехали с опозданием.","de":"Die Jungen sind zu spät angekommen.","en":"The boys arrived late.","uk":"Хлопці приїхали із запізненням.","fa":"پسرها با تأخیر رسیدند."}],"hints":{"ru":"Глаголы движения и изменения состояния (andare, venire, nascere, morire) берут essere; большинство переходных глаголов — avere. С essere меняй окончание причастия: -o, -a, -i, -e.","de":"Verben der Bewegung und Zustandsänderung (andare, venire, nascere, morire) verlangen essere; die meisten transitiven Verben avere. Mit essere passe die Partizipendung an: -o, -a, -i, -e.","en":"Verbs of motion and change of state (andare, venire, nascere, morire) take essere; most transitive verbs take avere. With essere change the participle ending: -o, -a, -i, -e.","uk":"Дієслова руху та зміни стану (andare, venire, nascere, morire) беруть essere; більшість перехідних дієслів — avere. З essere змінюй закінчення дієприкметника: -o, -a, -i, -e.","fa":"افعال حرکت و تغییر حالت (andare، venire، nascere، morire) با essere می‌آیند؛ بیشتر افعال متعدی با avere. با essere پایانهٔ اسم مفعول را تغییر بده: -o، -a، -i، -e."}},
{"id":"imperfetto","icon":"🎞️","level":"A2","title":{"it":"Imperfetto","ru":"Imperfetto (имперфект)","de":"Imperfetto (Imperfekt)","en":"Imperfetto (imperfect)","uk":"Imperfetto (імперфект)","fa":"ماضی استمراری (imperfetto)"},"intro":{"it":"L'imperfetto descrive azioni abituali o continue nel passato, descrizioni e situazioni di sfondo. Si forma dalla radice del verbo più le desinenze -vo, -vi, -va, -vamo, -vate, -vano. Solo essere è irregolare (ero, eri, era...).","ru":"Imperfetto описывает привычные или длительные действия в прошлом, описания и фон событий. Образуется от основы глагола плюс окончания -vo, -vi, -va, -vamo, -vate, -vano. Только essere неправильный (ero, eri, era...).","de":"Das Imperfetto beschreibt gewohnheitsmäßige oder andauernde Handlungen in der Vergangenheit, Beschreibungen und Hintergrundsituationen. Es wird aus dem Verbstamm plus den Endungen -vo, -vi, -va, -vamo, -vate, -vano gebildet. Nur essere ist unregelmäßig (ero, eri, era...).","en":"The imperfetto describes habitual or ongoing actions in the past, descriptions and background situations. It is formed from the verb stem plus the endings -vo, -vi, -va, -vamo, -vate, -vano. Only essere is irregular (ero, eri, era...).","uk":"Imperfetto описує звичні або тривалі дії в минулому, описи та тло подій. Утворюється від основи дієслова плюс закінчення -vo, -vi, -va, -vamo, -vate, -vano. Лише essere неправильне (ero, eri, era...).","fa":"ماضی استمراری کارهای عادتی یا مستمر در گذشته، توصیف‌ها و موقعیت‌های زمینه‌ای را بیان می‌کند. از ریشهٔ فعل به‌علاوهٔ پایانه‌های -vo، -vi، -va، -vamo، -vate، -vano ساخته می‌شود. فقط essere بی‌قاعده است (ero، eri، era...)."},"tables":[{"caption":{"it":"Desinenze regolari (parlare, prendere, dormire)","ru":"Правильные окончания (parlare, prendere, dormire)","de":"Regelmäßige Endungen (parlare, prendere, dormire)","en":"Regular endings (parlare, prendere, dormire)","uk":"Правильні закінчення (parlare, prendere, dormire)","fa":"پایانه‌های باقاعده (parlare، prendere، dormire)"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"-are","ru":"-are","de":"-are","en":"-are","uk":"-are","fa":"-are"},{"it":"-ere","ru":"-ere","de":"-ere","en":"-ere","uk":"-ere","fa":"-ere"},{"it":"-ire","ru":"-ire","de":"-ire","en":"-ire","uk":"-ire","fa":"-ire"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["parlavo","prendevo","dormivo"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["parlavi","prendevi","dormivi"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["parlava","prendeva","dormiva"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["parlavamo","prendevamo","dormivamo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["parlavate","prendevate","dormivate"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["parlavano","prendevano","dormivano"]}]},{"caption":{"it":"essere (irregolare)","ru":"essere (неправильный)","de":"essere (unregelmäßig)","en":"essere (irregular)","uk":"essere (неправильне)","fa":"essere (بی‌قاعده)"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"صورت"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["ero"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["eri"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["era"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["eravamo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["eravate"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["erano"]}]}],"examples":[{"it":"Da bambino giocavo sempre in giardino.","ru":"В детстве я всегда играл в саду.","de":"Als Kind spielte ich immer im Garten.","en":"As a child I always played in the garden.","uk":"У дитинстві я завжди грався в саду.","fa":"در کودکی همیشه در باغ بازی می‌کردم."},{"it":"Era una giornata fredda e pioveva.","ru":"Был холодный день, и шёл дождь.","de":"Es war ein kalter Tag und es regnete.","en":"It was a cold day and it was raining.","uk":"Був холодний день, і йшов дощ.","fa":"روزی سرد بود و باران می‌بارید."},{"it":"Mentre studiavo, ascoltavo la musica.","ru":"Пока я учился, я слушал музыку.","de":"Während ich lernte, hörte ich Musik.","en":"While I was studying, I was listening to music.","uk":"Поки я вчився, я слухав музику.","fa":"در حالی که درس می‌خواندم، موسیقی گوش می‌دادم."}],"hints":{"ru":"Имперфект часто идёт со словами sempre, di solito, ogni giorno, mentre. Он передаёт «как было» и незавершённый фон, а не одно завершённое событие.","de":"Das Imperfetto steht oft mit sempre, di solito, ogni giorno, mentre. Es beschreibt, „wie es war\", den unabgeschlossenen Hintergrund, nicht ein einzelnes abgeschlossenes Ereignis.","en":"The imperfetto often goes with sempre, di solito, ogni giorno, mentre. It conveys how things were, the unfinished background, not a single completed event.","uk":"Imperfetto часто вживається зі словами sempre, di solito, ogni giorno, mentre. Він передає «як було», незавершене тло, а не одну завершену подію.","fa":"ماضی استمراری اغلب با sempre، di solito، ogni giorno، mentre می‌آید. حالت و زمینهٔ پایان‌نیافته را بیان می‌کند، نه یک رویداد کاملِ منفرد."}},
{"id":"passato-imperfetto","icon":"⏳","level":"A2","title":{"it":"Passato prossimo vs imperfetto","ru":"Passato prossimo и imperfetto","de":"Passato prossimo vs. Imperfetto","en":"Passato prossimo vs imperfetto","uk":"Passato prossimo проти imperfetto","fa":"ماضی نقلی در برابر ماضی استمراری"},"intro":{"it":"Questi due tempi si oppongono. Il passato prossimo indica un'azione precisa e conclusa; l'imperfetto indica descrizioni, abitudini e azioni in corso di svolgimento. Spesso l'imperfetto è lo sfondo e il passato prossimo l'evento che interrompe.","ru":"Эти два времени противопоставляются. Passato prossimo обозначает конкретное завершённое действие; imperfetto — описания, привычки и действия в процессе. Часто imperfetto — это фон, а passato prossimo — событие, которое его прерывает.","de":"Diese beiden Zeiten stehen im Gegensatz. Das Passato prossimo bezeichnet eine bestimmte, abgeschlossene Handlung; das Imperfetto Beschreibungen, Gewohnheiten und andauernde Handlungen. Oft ist das Imperfetto der Hintergrund und das Passato prossimo das unterbrechende Ereignis.","en":"These two tenses contrast. The passato prossimo marks a specific, completed action; the imperfetto marks descriptions, habits and ongoing actions. Often the imperfetto is the background and the passato prossimo the event that interrupts it.","uk":"Ці два часи протиставляються. Passato prossimo позначає конкретну завершену дію; imperfetto — описи, звички та дії в процесі. Часто imperfetto — це тло, а passato prossimo — подія, що його перериває.","fa":"این دو زمان با هم در تقابل‌اند. ماضی نقلی کاری مشخص و پایان‌یافته را نشان می‌دهد؛ ماضی استمراری توصیف‌ها، عادت‌ها و کارهای در جریان را. اغلب ماضی استمراری زمینه است و ماضی نقلی رویدادی که آن را قطع می‌کند."},"tables":[{"caption":{"it":"Quando usare ciascun tempo","ru":"Когда использовать каждое время","de":"Wann welche Zeit verwenden","en":"When to use each tense","uk":"Коли вживати кожен час","fa":"چه زمانی از هر یک استفاده کنیم"},"labelHeader":{"it":"Uso","ru":"Употребление","de":"Gebrauch","en":"Use","uk":"Вживання","fa":"کاربرد"},"columns":[{"it":"Passato prossimo","ru":"Passato prossimo","de":"Passato prossimo","en":"Passato prossimo","uk":"Passato prossimo","fa":"Passato prossimo"},{"it":"Imperfetto","ru":"Imperfetto","de":"Imperfetto","en":"Imperfetto","uk":"Imperfetto","fa":"Imperfetto"}],"rows":[{"label":{"it":"Azione","ru":"Действие","de":"Handlung","en":"Action","uk":"Дія","fa":"کنش"},"cells":["ho letto un libro","leggevo un libro"]},{"label":{"it":"Tipo","ru":"Тип","de":"Typ","en":"Type","uk":"Тип","fa":"نوع"},"cells":["conclusa, puntuale","abituale, continua"]},{"label":{"it":"Spie","ru":"Маркеры","de":"Signalwörter","en":"Signal words","uk":"Маркери","fa":"نشانه‌ها"},"cells":["ieri, all'improvviso, una volta","sempre, mentre, di solito"]}]}],"examples":[{"it":"Mentre dormivo, è suonato il telefono.","ru":"Пока я спал, зазвонил телефон.","de":"Während ich schlief, klingelte das Telefon.","en":"While I was sleeping, the phone rang.","uk":"Поки я спав, задзвонив телефон.","fa":"در حالی که خوابیده بودم، تلفن زنگ خورد."},{"it":"Faceva bel tempo, così siamo usciti.","ru":"Была хорошая погода, поэтому мы вышли.","de":"Das Wetter war schön, deshalb sind wir ausgegangen.","en":"The weather was nice, so we went out.","uk":"Була гарна погода, тож ми вийшли.","fa":"هوا خوب بود، پس بیرون رفتیم."},{"it":"Ogni estate andavamo al mare, ma quell'anno siamo rimasti a casa.","ru":"Каждое лето мы ездили на море, но в тот год остались дома.","de":"Jeden Sommer fuhren wir ans Meer, aber in jenem Jahr blieben wir zu Hause.","en":"Every summer we went to the sea, but that year we stayed home.","uk":"Щоліта ми їздили на море, але того року залишилися вдома.","fa":"هر تابستان به دریا می‌رفتیم، اما آن سال در خانه ماندیم."}],"hints":{"ru":"Правило: длящийся фон = imperfetto; внезапное или единичное событие = passato prossimo. В одной фразе они часто сочетаются: mentre + imperfetto, затем passato prossimo.","de":"Faustregel: andauernder Hintergrund = Imperfetto; plötzliches oder einmaliges Ereignis = Passato prossimo. In einem Satz kombinieren sie sich oft: mentre + Imperfetto, dann Passato prossimo.","en":"Rule of thumb: ongoing background = imperfetto; sudden or one-off event = passato prossimo. In one sentence they often combine: mentre + imperfetto, then passato prossimo.","uk":"Правило: тривале тло = imperfetto; раптова чи одинична подія = passato prossimo. В одному реченні вони часто поєднуються: mentre + imperfetto, потім passato prossimo.","fa":"قاعدهٔ کلی: زمینهٔ در جریان = ماضی استمراری؛ رویداد ناگهانی یا یک‌باره = ماضی نقلی. در یک جمله اغلب با هم می‌آیند: mentre + استمراری، سپس نقلی."}},
{"id":"futuro-semplice","icon":"🔮","level":"A2","title":{"it":"Futuro semplice","ru":"Futuro semplice (простое будущее)","de":"Futuro semplice (Futur I)","en":"Futuro semplice (simple future)","uk":"Futuro semplice (простий майбутній)","fa":"آیندهٔ ساده (futuro semplice)"},"intro":{"it":"Il futuro semplice esprime azioni future e supposizioni. Si forma togliendo la vocale finale dell'infinito e aggiungendo le desinenze -ò, -ai, -à, -emo, -ete, -anno. I verbi in -are cambiano la a in e (parlare → parler-). Molti verbi hanno radici irregolari.","ru":"Futuro semplice выражает будущие действия и предположения. Образуется отбрасыванием конечной гласной инфинитива и добавлением окончаний -ò, -ai, -à, -emo, -ete, -anno. У глаголов на -are a меняется на e (parlare → parler-). У многих глаголов неправильные основы.","de":"Das Futuro semplice drückt zukünftige Handlungen und Vermutungen aus. Es wird gebildet, indem man den Endvokal des Infinitivs weglässt und die Endungen -ò, -ai, -à, -emo, -ete, -anno anhängt. Verben auf -are ändern das a zu e (parlare → parler-). Viele Verben haben unregelmäßige Stämme.","en":"The futuro semplice expresses future actions and suppositions. It is formed by dropping the final vowel of the infinitive and adding the endings -ò, -ai, -à, -emo, -ete, -anno. Verbs in -are change the a to e (parlare → parler-). Many verbs have irregular stems.","uk":"Futuro semplice виражає майбутні дії та припущення. Утворюється відкиданням кінцевого голосного інфінітива та додаванням закінчень -ò, -ai, -à, -emo, -ete, -anno. Дієслова на -are змінюють a на e (parlare → parler-). Багато дієслів мають неправильні основи.","fa":"آیندهٔ ساده کارهای آینده و گمان‌ها را بیان می‌کند. با حذف واکهٔ پایانی مصدر و افزودن پایانه‌های -ò، -ai، -à، -emo، -ete، -anno ساخته می‌شود. افعال -are حرف a را به e تبدیل می‌کنند (parlare → parler-). بسیاری از افعال ریشهٔ بی‌قاعده دارند."},"tables":[{"caption":{"it":"Verbo regolare (parlare)","ru":"Правильный глагол (parlare)","de":"Regelmäßiges Verb (parlare)","en":"Regular verb (parlare)","uk":"Правильне дієслово (parlare)","fa":"فعل باقاعده (parlare)"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"صورت"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["parlerò"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["parlerai"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["parlerà"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["parleremo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["parlerete"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["parleranno"]}]},{"caption":{"it":"Radici irregolari (io)","ru":"Неправильные основы (io)","de":"Unregelmäßige Stämme (io)","en":"Irregular stems (io)","uk":"Неправильні основи (io)","fa":"ریشه‌های بی‌قاعده (io)"},"labelHeader":{"it":"Verbo","ru":"Глагол","de":"Verb","en":"Verb","uk":"Дієслово","fa":"فعل"},"columns":[{"it":"Radice","ru":"Основа","de":"Stamm","en":"Stem","uk":"Основа","fa":"ریشه"},{"it":"Forma io","ru":"Форма io","de":"Form io","en":"io form","uk":"Форма io","fa":"صورت io"}],"rows":[{"label":{"it":"essere","ru":"essere","de":"essere","en":"essere","uk":"essere","fa":"essere"},"cells":["sar-","sarò"]},{"label":{"it":"avere","ru":"avere","de":"avere","en":"avere","uk":"avere","fa":"avere"},"cells":["avr-","avrò"]},{"label":{"it":"andare","ru":"andare","de":"andare","en":"andare","uk":"andare","fa":"andare"},"cells":["andr-","andrò"]},{"label":{"it":"fare","ru":"fare","de":"fare","en":"fare","uk":"fare","fa":"fare"},"cells":["far-","farò"]},{"label":{"it":"venire","ru":"venire","de":"venire","en":"venire","uk":"venire","fa":"venire"},"cells":["verr-","verrò"]}]}],"examples":[{"it":"Domani sarò a casa tutto il giorno.","ru":"Завтра я буду дома весь день.","de":"Morgen werde ich den ganzen Tag zu Hause sein.","en":"Tomorrow I will be at home all day.","uk":"Завтра я буду вдома цілий день.","fa":"فردا تمام روز خانه خواهم بود."},{"it":"L'anno prossimo andremo in Italia.","ru":"В следующем году мы поедем в Италию.","de":"Nächstes Jahr werden wir nach Italien fahren.","en":"Next year we will go to Italy.","uk":"Наступного року ми поїдемо до Італії.","fa":"سال آینده به ایتالیا خواهیم رفت."},{"it":"Avrà trent'anni, immagino.","ru":"Ему, наверное, лет тридцать.","de":"Er wird wohl dreißig Jahre alt sein, nehme ich an.","en":"He is probably thirty, I imagine.","uk":"Йому, мабуть, років тридцять.","fa":"گمان می‌کنم حدود سی سالش باشد."}],"hints":{"ru":"Запомни неправильные основы: essere→sar-, avere→avr-, andare→andr-, fare→far-, venire→verr-. Окончания одинаковы для всех глаголов. Будущее время также выражает предположение о настоящем.","de":"Merke dir die unregelmäßigen Stämme: essere→sar-, avere→avr-, andare→andr-, fare→far-, venire→verr-. Die Endungen sind für alle Verben gleich. Das Futur drückt auch eine Vermutung über die Gegenwart aus.","en":"Memorize the irregular stems: essere→sar-, avere→avr-, andare→andr-, fare→far-, venire→verr-. The endings are the same for all verbs. The future also expresses a supposition about the present.","uk":"Запам'ятай неправильні основи: essere→sar-, avere→avr-, andare→andr-, fare→far-, venire→verr-. Закінчення однакові для всіх дієслів. Майбутній час також виражає припущення про теперішнє.","fa":"ریشه‌های بی‌قاعده را حفظ کن: essere→sar-، avere→avr-، andare→andr-، fare→far-، venire→verr-. پایانه‌ها برای همهٔ افعال یکسان است. آینده گمان دربارهٔ زمان حال را نیز بیان می‌کند."}},
{"id":"verbi-riflessivi","icon":"🔄","level":"A2","title":{"it":"I verbi riflessivi","ru":"Возвратные глаголы","de":"Reflexive Verben","en":"Reflexive verbs","uk":"Зворотні дієслова","fa":"افعال انعکاسی"},"intro":{"it":"I verbi riflessivi (alzarsi, svegliarsi) usano i pronomi mi, ti, si, ci, vi, si. Al presente il pronome sta davanti al verbo. Nel passato prossimo si usa sempre essere e il participio concorda con il soggetto.","ru":"Возвратные глаголы (alzarsi, svegliarsi) используют местоимения mi, ti, si, ci, vi, si. В настоящем времени местоимение стоит перед глаголом. В passato prossimo всегда используется essere, а причастие согласуется с подлежащим.","de":"Reflexive Verben (alzarsi, svegliarsi) verwenden die Pronomen mi, ti, si, ci, vi, si. Im Präsens steht das Pronomen vor dem Verb. Im Passato prossimo wird immer essere verwendet und das Partizip richtet sich nach dem Subjekt.","en":"Reflexive verbs (alzarsi, svegliarsi) use the pronouns mi, ti, si, ci, vi, si. In the present tense the pronoun goes before the verb. In the passato prossimo you always use essere and the participle agrees with the subject.","uk":"Зворотні дієслова (alzarsi, svegliarsi) вживають займенники mi, ti, si, ci, vi, si. У теперішньому часі займенник стоїть перед дієсловом. У passato prossimo завжди вживається essere, а дієприкметник узгоджується з підметом.","fa":"افعال انعکاسی (alzarsi، svegliarsi) از ضمایر mi، ti، si، ci، vi، si استفاده می‌کنند. در زمان حال ضمیر پیش از فعل می‌آید. در passato prossimo همیشه از essere استفاده می‌شود و اسم مفعول با فاعل مطابقت می‌کند."},"tables":[{"caption":{"it":"Presente di alzarsi (alzarsi)","ru":"Настоящее время alzarsi","de":"Präsens von alzarsi","en":"Present tense of alzarsi","uk":"Теперішній час alzarsi","fa":"زمان حال alzarsi"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Pronome","ru":"Местоимение","de":"Pronomen","en":"Pronoun","uk":"Займенник","fa":"ضمیر"},{"it":"Verbo","ru":"Глагол","de":"Verb","en":"Verb","uk":"Дієслово","fa":"فعل"}],"rows":[{"label":{"it":"io","ru":"io","de":"io","en":"io","uk":"io","fa":"io"},"cells":["mi","alzo"]},{"label":{"it":"tu","ru":"tu","de":"tu","en":"tu","uk":"tu","fa":"tu"},"cells":["ti","alzi"]},{"label":{"it":"lui/lei","ru":"lui/lei","de":"lui/lei","en":"lui/lei","uk":"lui/lei","fa":"lui/lei"},"cells":["si","alza"]},{"label":{"it":"noi","ru":"noi","de":"noi","en":"noi","uk":"noi","fa":"noi"},"cells":["ci","alziamo"]},{"label":{"it":"voi","ru":"voi","de":"voi","en":"voi","uk":"voi","fa":"voi"},"cells":["vi","alzate"]},{"label":{"it":"loro","ru":"loro","de":"loro","en":"loro","uk":"loro","fa":"loro"},"cells":["si","alzano"]}]},{"caption":{"it":"Passato prossimo (essere + accordo)","ru":"Passato prossimo (essere + согласование)","de":"Passato prossimo (essere + Angleichung)","en":"Passato prossimo (essere + agreement)","uk":"Passato prossimo (essere + узгодження)","fa":"Passato prossimo (essere + مطابقت)"},"labelHeader":{"it":"Soggetto","ru":"Подлежащее","de":"Subjekt","en":"Subject","uk":"Підмет","fa":"فاعل"},"columns":[{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"شکل"}],"rows":[{"label":{"it":"io (m.)","ru":"io (м.)","de":"io (m.)","en":"io (m.)","uk":"io (ч.)","fa":"io (مذکر)"},"cells":["mi sono alzato"]},{"label":{"it":"io (f.)","ru":"io (ж.)","de":"io (f.)","en":"io (f.)","uk":"io (ж.)","fa":"io (مؤنث)"},"cells":["mi sono alzata"]},{"label":{"it":"noi (m.)","ru":"noi (м.)","de":"noi (m.)","en":"noi (m.)","uk":"noi (ч.)","fa":"noi (مذکر)"},"cells":["ci siamo alzati"]},{"label":{"it":"loro (f.)","ru":"loro (ж.)","de":"loro (f.)","en":"loro (f.)","uk":"loro (ж.)","fa":"loro (مؤنث)"},"cells":["si sono alzate"]}]}],"examples":[{"it":"Mi sveglio alle sette ogni mattina.","ru":"Я просыпаюсь в семь каждое утро.","de":"Ich wache jeden Morgen um sieben auf.","en":"I wake up at seven every morning.","uk":"Я прокидаюся о сьомій щоранку.","fa":"من هر روز صبح ساعت هفت بیدار می‌شوم."},{"it":"Maria si è alzata tardi ieri.","ru":"Мария вчера встала поздно.","de":"Maria ist gestern spät aufgestanden.","en":"Maria got up late yesterday.","uk":"Марія вчора встала пізно.","fa":"دیروز ماریا دیر از خواب بلند شد."},{"it":"Ci laviamo le mani prima di mangiare.","ru":"Мы моем руки перед едой.","de":"Wir waschen uns die Hände vor dem Essen.","en":"We wash our hands before eating.","uk":"Ми миємо руки перед їдою.","fa":"ما پیش از غذا خوردن دست‌هایمان را می‌شوییم."}],"hints":{"ru":"В passato prossimo причастие всегда согласуется в роде и числе с подлежащим: si è alzato / si è alzata.","de":"Im Passato prossimo richtet sich das Partizip immer in Geschlecht und Zahl nach dem Subjekt: si è alzato / si è alzata.","en":"In the passato prossimo the participle always agrees in gender and number with the subject: si è alzato / si è alzata.","uk":"У passato prossimo дієприкметник завжди узгоджується в роді й числі з підметом: si è alzato / si è alzata.","fa":"در passato prossimo اسم مفعول همیشه در جنس و شمار با فاعل مطابقت می‌کند: si è alzato / si è alzata."}},
{"id":"pronomi-diretti-indiretti","icon":"🎯","level":"A2","title":{"it":"Pronomi diretti e indiretti","ru":"Прямые и косвенные местоимения","de":"Direkte und indirekte Pronomen","en":"Direct and indirect object pronouns","uk":"Прямі та непрямі займенники","fa":"ضمایر مفعولی مستقیم و غیرمستقیم"},"intro":{"it":"I pronomi diretti (lo, la, li, le) sostituiscono l'oggetto diretto; quelli indiretti (gli, le) sostituiscono l'oggetto con la preposizione a. Con lo, la, li, le nel passato prossimo il participio concorda con il pronome.","ru":"Прямые местоимения (lo, la, li, le) заменяют прямое дополнение; косвенные (gli, le) заменяют дополнение с предлогом a. С lo, la, li, le в passato prossimo причастие согласуется с местоимением.","de":"Direkte Pronomen (lo, la, li, le) ersetzen das direkte Objekt; indirekte (gli, le) ersetzen das Objekt mit der Präposition a. Mit lo, la, li, le richtet sich das Partizip im Passato prossimo nach dem Pronomen.","en":"Direct pronouns (lo, la, li, le) replace the direct object; indirect ones (gli, le) replace the object with the preposition a. With lo, la, li, le the participle agrees with the pronoun in the passato prossimo.","uk":"Прямі займенники (lo, la, li, le) замінюють прямий додаток; непрямі (gli, le) замінюють додаток із прийменником a. З lo, la, li, le дієприкметник у passato prossimo узгоджується із займенником.","fa":"ضمایر مستقیم (lo، la، li، le) جایگزین مفعول مستقیم می‌شوند؛ ضمایر غیرمستقیم (gli، le) جایگزین مفعول همراه با حرف اضافه a می‌شوند. با lo، la، li، le اسم مفعول در passato prossimo با ضمیر مطابقت می‌کند."},"tables":[{"caption":{"it":"Pronomi diretti e indiretti","ru":"Прямые и косвенные местоимения","de":"Direkte und indirekte Pronomen","en":"Direct and indirect pronouns","uk":"Прямі та непрямі займенники","fa":"ضمایر مستقیم و غیرمستقیم"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"Diretto","ru":"Прямое","de":"Direkt","en":"Direct","uk":"Прямий","fa":"مستقیم"},{"it":"Indiretto","ru":"Косвенное","de":"Indirekt","en":"Indirect","uk":"Непрямий","fa":"غیرمستقیم"}],"rows":[{"label":{"it":"lui (m.)","ru":"он","de":"er","en":"him","uk":"він","fa":"او (مذکر)"},"cells":["lo","gli"]},{"label":{"it":"lei (f.)","ru":"она","de":"sie","en":"her","uk":"вона","fa":"او (مؤنث)"},"cells":["la","le"]},{"label":{"it":"loro (m.)","ru":"они (м.)","de":"sie (m.)","en":"them (m.)","uk":"вони (ч.)","fa":"آن‌ها (مذکر)"},"cells":["li","gli"]},{"label":{"it":"loro (f.)","ru":"они (ж.)","de":"sie (f.)","en":"them (f.)","uk":"вони (ж.)","fa":"آن‌ها (مؤنث)"},"cells":["le","gli"]}]},{"caption":{"it":"Accordo del participio con il pronome diretto","ru":"Согласование причастия с прямым местоимением","de":"Angleichung des Partizips an das direkte Pronomen","en":"Participle agreement with the direct pronoun","uk":"Узгодження дієприкметника з прямим займенником","fa":"مطابقت اسم مفعول با ضمیر مستقیم"},"labelHeader":{"it":"Pronome","ru":"Местоимение","de":"Pronomen","en":"Pronoun","uk":"Займенник","fa":"ضمیر"},"columns":[{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"lo","ru":"lo","de":"lo","en":"lo","uk":"lo","fa":"lo"},"cells":["L'ho visto"]},{"label":{"it":"la","ru":"la","de":"la","en":"la","uk":"la","fa":"la"},"cells":["L'ho vista"]},{"label":{"it":"li","ru":"li","de":"li","en":"li","uk":"li","fa":"li"},"cells":["Li ho visti"]},{"label":{"it":"le","ru":"le","de":"le","en":"le","uk":"le","fa":"le"},"cells":["Le ho viste"]}]}],"examples":[{"it":"Conosci Anna? Sì, la conosco bene.","ru":"Ты знаешь Анну? Да, я её хорошо знаю.","de":"Kennst du Anna? Ja, ich kenne sie gut.","en":"Do you know Anna? Yes, I know her well.","uk":"Ти знаєш Анну? Так, я її добре знаю.","fa":"آنا را می‌شناسی؟ بله، او را خوب می‌شناسم."},{"it":"Ho scritto a Marco: gli ho mandato un messaggio.","ru":"Я написал Марко: я отправил ему сообщение.","de":"Ich habe Marco geschrieben: ich habe ihm eine Nachricht geschickt.","en":"I wrote to Marco: I sent him a message.","uk":"Я написав Марко: я надіслав йому повідомлення.","fa":"به مارکو نوشتم: برایش یک پیام فرستادم."},{"it":"Le chiavi? Le ho lasciate sul tavolo.","ru":"Ключи? Я оставил их на столе.","de":"Die Schlüssel? Ich habe sie auf dem Tisch gelassen.","en":"The keys? I left them on the table.","uk":"Ключі? Я залишив їх на столі.","fa":"کلیدها؟ آن‌ها را روی میز گذاشتم."}],"hints":{"ru":"Не путайте: le перед глаголом = «ей» (косвенное) или «их, ж. р.» (прямое); gli = «ему» и в разговорном языке «им».","de":"Nicht verwechseln: le vor dem Verb = „ihr“ (indirekt) oder „sie, Pl. f.“ (direkt); gli = „ihm“ und umgangssprachlich auch „ihnen“.","en":"Don't confuse them: le before the verb = 'to her' (indirect) or 'them, fem.' (direct); gli = 'to him' and colloquially 'to them'.","uk":"Не плутайте: le перед дієсловом = «їй» (непрямий) або «їх, ж. р.» (прямий); gli = «йому» і в розмовній мові «їм».","fa":"اشتباه نگیرید: le پیش از فعل = «به او (مؤنث)» (غیرمستقیم) یا «آن‌ها، مؤنث» (مستقیم)؛ gli = «به او (مذکر)» و در گفتار «به آن‌ها»."}},
{"id":"ci-ne","icon":"📍","level":"A2","title":{"it":"Le particelle ci e ne","ru":"Частицы ci и ne","de":"Die Partikeln ci und ne","en":"The particles ci and ne","uk":"Частки ci та ne","fa":"ذرات ci و ne"},"intro":{"it":"Ci sostituisce un luogo (a, in, su + posto) e significa «lì, ci». Ne sostituisce di + qualcosa ed esprime una parte o una quantità («di ciò, ne»). Entrambe vanno prima del verbo.","ru":"Ci заменяет место (a, in, su + место) и означает «там, туда». Ne заменяет di + что-то и выражает часть или количество («об этом, из этого»). Обе частицы стоят перед глаголом.","de":"Ci ersetzt einen Ort (a, in, su + Ort) und bedeutet „dort, dorthin“. Ne ersetzt di + etwas und drückt einen Teil oder eine Menge aus („davon“). Beide stehen vor dem Verb.","en":"Ci replaces a place (a, in, su + place) and means 'there'. Ne replaces di + something and expresses a part or a quantity ('of it, some'). Both go before the verb.","uk":"Ci замінює місце (a, in, su + місце) і означає «там, туди». Ne замінює di + щось і виражає частину чи кількість («з цього, про це»). Обидві стоять перед дієсловом.","fa":"ci جایگزین یک مکان می‌شود (a، in، su + مکان) و به معنای «آنجا» است. ne جایگزین di + چیزی می‌شود و بخش یا مقدار را بیان می‌کند («از آن»). هر دو پیش از فعل می‌آیند."},"tables":[{"caption":{"it":"Ci (luogo) e ne (quantità)","ru":"Ci (место) и ne (количество)","de":"Ci (Ort) und ne (Menge)","en":"Ci (place) and ne (quantity)","uk":"Ci (місце) та ne (кількість)","fa":"ci (مکان) و ne (مقدار)"},"labelHeader":{"it":"Particella","ru":"Частица","de":"Partikel","en":"Particle","uk":"Частка","fa":"ذره"},"columns":[{"it":"Sostituisce","ru":"Заменяет","de":"Ersetzt","en":"Replaces","uk":"Замінює","fa":"جایگزین"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"ci","ru":"ci","de":"ci","en":"ci","uk":"ci","fa":"ci"},"cells":["a/in/su + luogo","Ci vado domani"]},{"label":{"it":"ci","ru":"ci","de":"ci","en":"ci","uk":"ci","fa":"ci"},"cells":["a + cosa","Ci penso io"]},{"label":{"it":"ne","ru":"ne","de":"ne","en":"ne","uk":"ne","fa":"ne"},"cells":["di + quantità","Ne voglio due"]},{"label":{"it":"ne","ru":"ne","de":"ne","en":"ne","uk":"ne","fa":"ne"},"cells":["di + argomento","Ne parliamo dopo"]}]}],"examples":[{"it":"Vai spesso in palestra? Sì, ci vado ogni giorno.","ru":"Ты часто ходишь в спортзал? Да, я хожу туда каждый день.","de":"Gehst du oft ins Fitnessstudio? Ja, ich gehe jeden Tag hin.","en":"Do you often go to the gym? Yes, I go there every day.","uk":"Ти часто ходиш до спортзалу? Так, я ходжу туди щодня.","fa":"زیاد به باشگاه می‌روی؟ بله، هر روز به آنجا می‌روم."},{"it":"Quanti caffè bevi? Ne bevo tre al giorno.","ru":"Сколько кофе ты пьёшь? Я пью его три чашки в день.","de":"Wie viele Kaffee trinkst du? Ich trinke drei davon pro Tag.","en":"How many coffees do you drink? I drink three of them a day.","uk":"Скільки кави ти п'єш? Я п'ю три чашки на день.","fa":"چند قهوه می‌نوشی؟ روزی سه‌تا از آن می‌نوشم."},{"it":"Hai bisogno di aiuto? No, grazie, non ne ho bisogno.","ru":"Тебе нужна помощь? Нет, спасибо, она мне не нужна.","de":"Brauchst du Hilfe? Nein, danke, ich brauche keine.","en":"Do you need help? No, thanks, I don't need any.","uk":"Тобі потрібна допомога? Ні, дякую, вона мені не потрібна.","fa":"به کمک نیاز داری؟ نه، ممنون، به آن نیازی ندارم."}],"hints":{"ru":"После ne с количеством в прошедшем времени причастие согласуется: «Ne ho comprati due» (два, м. р.).","de":"Nach ne mit Mengenangabe richtet sich das Partizip in der Vergangenheit: „Ne ho comprati due“ (zwei, m.).","en":"After ne with a quantity, the past participle agrees: 'Ne ho comprati due' (two, masc.).","uk":"Після ne з кількістю дієприкметник у минулому узгоджується: «Ne ho comprati due» (два, ч. р.).","fa":"پس از ne همراه با مقدار، اسم مفعول در گذشته مطابقت می‌کند: «Ne ho comprati due» (دو، مذکر)."}},
{"id":"comparativo-superlativo","icon":"📊","level":"A2","title":{"it":"Comparativo e superlativo","ru":"Сравнительная и превосходная степень","de":"Komparativ und Superlativ","en":"Comparative and superlative","uk":"Вищий і найвищий ступінь","fa":"صفت تفضیلی و عالی"},"intro":{"it":"Il comparativo usa più/meno ... di (davanti a nomi e pronomi) o più/meno ... che (tra due elementi dello stesso tipo), e così ... come per l'uguaglianza. Il superlativo relativo è il più ...; quello assoluto si forma con -issimo. Alcuni aggettivi sono irregolari: migliore, peggiore.","ru":"Сравнительная степень использует più/meno ... di (перед существительными и местоимениями) или più/meno ... che (между двумя однотипными элементами), а così ... come — для равенства. Относительная превосходная — il più ...; абсолютная образуется с -issimo. Некоторые прилагательные неправильные: migliore, peggiore.","de":"Der Komparativ verwendet più/meno ... di (vor Nomen und Pronomen) oder più/meno ... che (zwischen zwei gleichartigen Elementen) und così ... come für Gleichheit. Der relative Superlativ ist il più ...; der absolute wird mit -issimo gebildet. Einige Adjektive sind unregelmäßig: migliore, peggiore.","en":"The comparative uses più/meno ... di (before nouns and pronouns) or più/meno ... che (between two elements of the same kind), and così ... come for equality. The relative superlative is il più ...; the absolute is formed with -issimo. Some adjectives are irregular: migliore, peggiore.","uk":"Вищий ступінь уживає più/meno ... di (перед іменниками й займенниками) або più/meno ... che (між двома однотипними елементами), а così ... come — для рівності. Відносний найвищий — il più ...; абсолютний утворюється з -issimo. Деякі прикметники неправильні: migliore, peggiore.","fa":"صفت تفضیلی از più/meno ... di (پیش از اسم و ضمیر) یا più/meno ... che (میان دو عنصر هم‌نوع) و از così ... come برای برابری استفاده می‌کند. صفت عالی نسبی il più ... است؛ صفت عالی مطلق با -issimo ساخته می‌شود. برخی صفت‌ها بی‌قاعده‌اند: migliore، peggiore."},"tables":[{"caption":{"it":"Forme del comparativo","ru":"Формы сравнительной степени","de":"Formen des Komparativs","en":"Comparative forms","uk":"Форми вищого ступеня","fa":"شکل‌های صفت تفضیلی"},"labelHeader":{"it":"Tipo","ru":"Тип","de":"Typ","en":"Type","uk":"Тип","fa":"نوع"},"columns":[{"it":"Struttura","ru":"Структура","de":"Struktur","en":"Structure","uk":"Структура","fa":"ساختار"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"maggioranza (di)","ru":"больше (di)","de":"mehr (di)","en":"more (di)","uk":"більше (di)","fa":"بیشتر (di)"},"cells":["più ... di","più alto di Marco"]},{"label":{"it":"minoranza (che)","ru":"меньше (che)","de":"weniger (che)","en":"less (che)","uk":"менше (che)","fa":"کمتر (che)"},"cells":["meno ... che","meno caro che utile"]},{"label":{"it":"uguaglianza","ru":"равенство","de":"Gleichheit","en":"equality","uk":"рівність","fa":"برابری"},"cells":["così ... come","così alto come te"]}]},{"caption":{"it":"Superlativo e irregolari","ru":"Превосходная степень и неправильные формы","de":"Superlativ und unregelmäßige Formen","en":"Superlative and irregulars","uk":"Найвищий ступінь та неправильні форми","fa":"صفت عالی و بی‌قاعده‌ها"},"labelHeader":{"it":"Aggettivo","ru":"Прилагательное","de":"Adjektiv","en":"Adjective","uk":"Прикметник","fa":"صفت"},"columns":[{"it":"Superlativo relativo","ru":"Относительная","de":"Relativer Superlativ","en":"Relative superlative","uk":"Відносний","fa":"عالی نسبی"},{"it":"Superlativo assoluto","ru":"Абсолютная","de":"Absoluter Superlativ","en":"Absolute superlative","uk":"Абсолютний","fa":"عالی مطلق"}],"rows":[{"label":{"it":"grande","ru":"grande","de":"grande","en":"grande","uk":"grande","fa":"grande"},"cells":["il più grande","grandissimo"]},{"label":{"it":"buono","ru":"buono","de":"buono","en":"buono","uk":"buono","fa":"buono"},"cells":["il migliore","ottimo"]},{"label":{"it":"cattivo","ru":"cattivo","de":"cattivo","en":"cattivo","uk":"cattivo","fa":"cattivo"},"cells":["il peggiore","pessimo"]}]}],"examples":[{"it":"Luca è più alto di suo fratello.","ru":"Лука выше своего брата.","de":"Luca ist größer als sein Bruder.","en":"Luca is taller than his brother.","uk":"Лука вищий за свого брата.","fa":"لوکا از برادرش قدبلندتر است."},{"it":"Questo ristorante è il migliore della città.","ru":"Этот ресторан лучший в городе.","de":"Dieses Restaurant ist das beste der Stadt.","en":"This restaurant is the best in the city.","uk":"Цей ресторан найкращий у місті.","fa":"این رستوران بهترینِ شهر است."},{"it":"Il caffè qui è buonissimo!","ru":"Кофе здесь очень вкусный!","de":"Der Kaffee hier ist sehr gut!","en":"The coffee here is really good!","uk":"Кава тут дуже смачна!","fa":"قهوهٔ اینجا خیلی خوب است!"}],"hints":{"ru":"Используйте di перед существительным/местоимением, che — при сравнении двух прилагательных, глаголов или после предлога: «più che altro».","de":"Verwenden Sie di vor Nomen/Pronomen, che beim Vergleich zweier Adjektive, Verben oder nach einer Präposition: „più che altro“.","en":"Use di before a noun/pronoun, and che when comparing two adjectives, verbs, or after a preposition: 'più che altro'.","uk":"Уживайте di перед іменником/займенником, che — при порівнянні двох прикметників, дієслів або після прийменника: «più che altro».","fa":"پیش از اسم/ضمیر از di و هنگام مقایسهٔ دو صفت، فعل یا پس از حرف اضافه از che استفاده کنید: «più che altro»."}},
{"id":"condizionale","icon":"🕊️","level":"B1","title":{"it":"Il condizionale (presente e passato)","ru":"Условное наклонение (настоящее и прошедшее)","de":"Der Konditional (Gegenwart und Vergangenheit)","en":"The conditional (present and past)","uk":"Умовний спосіб (теперішній і минулий)","fa":"وجه شرطی (حال و گذشته)"},"intro":{"it":"Il condizionale esprime cortesia (vorrei un caffè), desideri e ipotesi (comprerei una casa), e il «futuro nel passato» (disse che sarebbe venuto). Il presente si forma dalla radice del futuro + le desinenze -ei, -esti, -ebbe, -emmo, -este, -ebbero; il passato usa avrei/sarei + participio.","ru":"Условное наклонение выражает вежливость (vorrei un caffè — я бы хотел кофе), желания и предположения (comprerei una casa — я бы купил дом) и «будущее в прошедшем» (disse che sarebbe venuto — он сказал, что придёт). Настоящее образуется от основы будущего времени + окончания -ei, -esti, -ebbe, -emmo, -este, -ebbero; прошедшее — avrei/sarei + причастие.","de":"Der Konditional drückt Höflichkeit (vorrei un caffè — ich hätte gern einen Kaffee), Wünsche und Hypothesen (comprerei una casa — ich würde ein Haus kaufen) sowie die «Zukunft in der Vergangenheit» (disse che sarebbe venuto — er sagte, er würde kommen) aus. Die Gegenwart wird aus dem Futurstamm + Endungen -ei, -esti, -ebbe, -emmo, -este, -ebbero gebildet; die Vergangenheit mit avrei/sarei + Partizip.","en":"The conditional expresses politeness (vorrei un caffè — I'd like a coffee), wishes and hypotheses (comprerei una casa — I would buy a house), and the ‘future-in-the-past' (disse che sarebbe venuto — he said he would come). The present is formed from the future stem + endings -ei, -esti, -ebbe, -emmo, -este, -ebbero; the past uses avrei/sarei + participle.","uk":"Умовний спосіб виражає ввічливість (vorrei un caffè — я хотів би кави), бажання й припущення (comprerei una casa — я купив би дім) та «майбутнє в минулому» (disse che sarebbe venuto — він сказав, що прийде). Теперішній час утворюється від основи майбутнього + закінчення -ei, -esti, -ebbe, -emmo, -este, -ebbero; минулий — avrei/sarei + дієприкметник.","fa":"وجه شرطی برای بیان ادب (vorrei un caffè — یک قهوه می‌خواستم)، آرزوها و فرض‌ها (comprerei una casa — یک خانه می‌خریدم) و «آینده در گذشته» (disse che sarebbe venuto — گفت که خواهد آمد) به کار می‌رود. زمان حال از ریشهٔ آینده + پایانه‌های -ei, -esti, -ebbe, -emmo, -este, -ebbero ساخته می‌شود؛ زمان گذشته با avrei/sarei + اسم مفعول."},"tables":[{"caption":{"it":"Condizionale presente: parlare, prendere, dormire","ru":"Настоящее условное: parlare, prendere, dormire","de":"Konditional Gegenwart: parlare, prendere, dormire","en":"Present conditional: parlare, prendere, dormire","uk":"Теперішній умовний: parlare, prendere, dormire","fa":"شرطی حال: parlare, prendere, dormire"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"parlare","ru":"parlare (говорить)","de":"parlare (sprechen)","en":"parlare (to speak)","uk":"parlare (говорити)","fa":"parlare (حرف زدن)"},{"it":"prendere","ru":"prendere (брать)","de":"prendere (nehmen)","en":"prendere (to take)","uk":"prendere (брати)","fa":"prendere (گرفتن)"},{"it":"dormire","ru":"dormire (спать)","de":"dormire (schlafen)","en":"dormire (to sleep)","uk":"dormire (спати)","fa":"dormire (خوابیدن)"}],"rows":[{"label":{"it":"io","ru":"io (я)","de":"io (ich)","en":"io (I)","uk":"io (я)","fa":"io (من)"},"cells":["parlerei","prenderei","dormirei"]},{"label":{"it":"tu","ru":"tu (ты)","de":"tu (du)","en":"tu (you)","uk":"tu (ти)","fa":"tu (تو)"},"cells":["parleresti","prenderesti","dormiresti"]},{"label":{"it":"lui/lei","ru":"lui/lei (он/она)","de":"lui/lei (er/sie)","en":"lui/lei (he/she)","uk":"lui/lei (він/вона)","fa":"lui/lei (او)"},"cells":["parlerebbe","prenderebbe","dormirebbe"]},{"label":{"it":"noi","ru":"noi (мы)","de":"noi (wir)","en":"noi (we)","uk":"noi (ми)","fa":"noi (ما)"},"cells":["parleremmo","prenderemmo","dormiremmo"]},{"label":{"it":"voi","ru":"voi (вы)","de":"voi (ihr)","en":"voi (you pl.)","uk":"voi (ви)","fa":"voi (شما)"},"cells":["parlereste","prendereste","dormireste"]},{"label":{"it":"loro","ru":"loro (они)","de":"loro (sie)","en":"loro (they)","uk":"loro (вони)","fa":"loro (آنها)"},"cells":["parlerebbero","prenderebbero","dormirebbero"]}]},{"caption":{"it":"Condizionale passato e verbi irregolari","ru":"Прошедшее условное и неправильные глаголы","de":"Konditional Vergangenheit und unregelmäßige Verben","en":"Past conditional and irregular verbs","uk":"Минулий умовний і неправильні дієслова","fa":"شرطی گذشته و افعال بی‌قاعده"},"labelHeader":{"it":"Forma","ru":"Форма","de":"Form","en":"Form","uk":"Форма","fa":"صورت"},"columns":[{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"passato (avere)","ru":"прошедшее (avere)","de":"Vergangenheit (avere)","en":"past (avere)","uk":"минулий (avere)","fa":"گذشته (avere)"},"cells":["avrei parlato"]},{"label":{"it":"passato (essere)","ru":"прошедшее (essere)","de":"Vergangenheit (essere)","en":"past (essere)","uk":"минулий (essere)","fa":"گذشته (essere)"},"cells":["sarei andato/a"]},{"label":{"it":"essere","ru":"essere (быть)","de":"essere (sein)","en":"essere (to be)","uk":"essere (бути)","fa":"essere (بودن)"},"cells":["sarei"]},{"label":{"it":"avere","ru":"avere (иметь)","de":"avere (haben)","en":"avere (to have)","uk":"avere (мати)","fa":"avere (داشتن)"},"cells":["avrei"]},{"label":{"it":"fare","ru":"fare (делать)","de":"fare (machen)","en":"fare (to do)","uk":"fare (робити)","fa":"fare (انجام دادن)"},"cells":["farei"]},{"label":{"it":"andare","ru":"andare (идти)","de":"andare (gehen)","en":"andare (to go)","uk":"andare (йти)","fa":"andare (رفتن)"},"cells":["andrei"]},{"label":{"it":"volere","ru":"volere (хотеть)","de":"volere (wollen)","en":"volere (to want)","uk":"volere (хотіти)","fa":"volere (خواستن)"},"cells":["vorrei"]}]}],"examples":[{"it":"Vorrei un caffè, per favore.","ru":"Я бы хотел кофе, пожалуйста.","de":"Ich hätte gern einen Kaffee, bitte.","en":"I would like a coffee, please.","uk":"Я хотів би каву, будь ласка.","fa":"یک قهوه می‌خواستم، لطفاً."},{"it":"Al posto tuo, non lo direi a nessuno.","ru":"На твоём месте я бы никому этого не сказал.","de":"An deiner Stelle würde ich es niemandem sagen.","en":"If I were you, I wouldn't tell anyone.","uk":"На твоєму місці я нікому б цього не сказав.","fa":"اگر جای تو بودم، به کسی نمی‌گفتم."},{"it":"Aveva promesso che sarebbe arrivato prima delle otto.","ru":"Он обещал, что приедет раньше восьми.","de":"Er hatte versprochen, dass er vor acht ankommen würde.","en":"He had promised that he would arrive before eight.","uk":"Він обіцяв, що приїде раніше восьмої.","fa":"قول داده بود که پیش از ساعت هشت خواهد رسید."}],"hints":{"ru":"Основа условного = основа будущего времени, поэтому неправильные глаголы совпадают: vorrei как verrò, andrei как andrò.","de":"Der Konditionalstamm = der Futurstamm, daher stimmen die unregelmäßigen Formen überein: vorrei wie verrò, andrei wie andrò.","en":"The conditional stem = the future stem, so the irregulars match: vorrei like verrò, andrei like andrò.","uk":"Основа умовного способу = основа майбутнього, тому неправильні збігаються: vorrei як verrò, andrei як andrò.","fa":"ریشهٔ شرطی همان ریشهٔ آینده است، پس افعال بی‌قاعده یکسان‌اند: vorrei مانند verrò و andrei مانند andrò."}},
{"id":"congiuntivo-presente","icon":"🌱","level":"B1","title":{"it":"Il congiuntivo presente","ru":"Настоящее сослагательное наклонение","de":"Der Konjunktiv Präsens","en":"The present subjunctive","uk":"Теперішній кон'юнктив","fa":"وجه التزامی حال"},"intro":{"it":"Il congiuntivo esprime opinione, dubbio, desiderio o emozione, non un fatto. Compare in frasi subordinate dopo espressioni come penso che, è importante che, benché, affinché, prima che. Le desinenze sono uguali per le tre persone singolari: -i (verbi in -are) / -a (verbi in -ere/-ire), spesso con «che» + soggetto.","ru":"Сослагательное наклонение выражает мнение, сомнение, желание или эмоцию, а не факт. Оно появляется в придаточных после выражений penso che, è importante che, benché, affinché, prima che. Окончания одинаковы для трёх лиц единственного числа: -i (глаголы на -are) / -a (глаголы на -ere/-ire), часто с «che» + подлежащее.","de":"Der Konjunktiv drückt Meinung, Zweifel, Wunsch oder Emotion aus, keine Tatsache. Er erscheint in Nebensätzen nach Ausdrücken wie penso che, è importante che, benché, affinché, prima che. Die Endungen sind für die drei Singularpersonen gleich: -i (Verben auf -are) / -a (Verben auf -ere/-ire), oft mit «che» + Subjekt.","en":"The subjunctive expresses opinion, doubt, wish or emotion, not a fact. It appears in subordinate clauses after expressions like penso che, è importante che, benché, affinché, prima che. The endings are the same for the three singular persons: -i (-are verbs) / -a (-ere/-ire verbs), usually with ‘che' + subject.","uk":"Кон'юнктив виражає думку, сумнів, бажання чи емоцію, а не факт. Він з'являється в підрядних реченнях після виразів penso che, è importante che, benché, affinché, prima che. Закінчення однакові для трьох осіб однини: -i (дієслова на -are) / -a (дієслова на -ere/-ire), зазвичай з «che» + підмет.","fa":"وجه التزامی نظر، شک، آرزو یا احساس را بیان می‌کند، نه یک واقعیت. در جملات پیرو پس از عباراتی مانند penso che, è importante che, benché, affinché, prima che می‌آید. پایانه‌ها برای سه شخص مفرد یکسان‌اند: -i (افعال -are) / -a (افعال -ere/-ire)، معمولاً با «che» + فاعل."},"tables":[{"caption":{"it":"Congiuntivo presente: parlare, prendere, capire","ru":"Настоящее сослагательное: parlare, prendere, capire","de":"Konjunktiv Präsens: parlare, prendere, capire","en":"Present subjunctive: parlare, prendere, capire","uk":"Теперішній кон'юнктив: parlare, prendere, capire","fa":"التزامی حال: parlare, prendere, capire"},"labelHeader":{"it":"che + persona","ru":"che + лицо","de":"che + Person","en":"che + person","uk":"che + особа","fa":"che + شخص"},"columns":[{"it":"parlare","ru":"parlare (говорить)","de":"parlare (sprechen)","en":"parlare (to speak)","uk":"parlare (говорити)","fa":"parlare (حرف زدن)"},{"it":"prendere","ru":"prendere (брать)","de":"prendere (nehmen)","en":"prendere (to take)","uk":"prendere (брати)","fa":"prendere (گرفتن)"},{"it":"capire (-isc-)","ru":"capire (понимать)","de":"capire (verstehen)","en":"capire (to understand)","uk":"capire (розуміти)","fa":"capire (فهمیدن)"}],"rows":[{"label":{"it":"che io","ru":"che io (что я)","de":"che io (dass ich)","en":"che io (that I)","uk":"che io (що я)","fa":"che io (که من)"},"cells":["parli","prenda","capisca"]},{"label":{"it":"che tu","ru":"che tu (что ты)","de":"che tu (dass du)","en":"che tu (that you)","uk":"che tu (що ти)","fa":"che tu (که تو)"},"cells":["parli","prenda","capisca"]},{"label":{"it":"che lui/lei","ru":"che lui/lei (что он/она)","de":"che lui/lei (dass er/sie)","en":"che lui/lei (that he/she)","uk":"che lui/lei (що він/вона)","fa":"che lui/lei (که او)"},"cells":["parli","prenda","capisca"]},{"label":{"it":"che noi","ru":"che noi (что мы)","de":"che noi (dass wir)","en":"che noi (that we)","uk":"che noi (що ми)","fa":"che noi (که ما)"},"cells":["parliamo","prendiamo","capiamo"]},{"label":{"it":"che voi","ru":"che voi (что вы)","de":"che voi (dass ihr)","en":"che voi (that you pl.)","uk":"che voi (що ви)","fa":"che voi (که شما)"},"cells":["parliate","prendiate","capiate"]},{"label":{"it":"che loro","ru":"che loro (что они)","de":"che loro (dass sie)","en":"che loro (that they)","uk":"che loro (що вони)","fa":"che loro (که آنها)"},"cells":["parlino","prendano","capiscano"]}]},{"caption":{"it":"Verbi irregolari e parole che richiedono il congiuntivo","ru":"Неправильные глаголы и слова, требующие сослагательного","de":"Unregelmäßige Verben und Auslöser des Konjunktivs","en":"Irregular verbs and words that trigger the subjunctive","uk":"Неправильні дієслова й слова, що вимагають кон'юнктива","fa":"افعال بی‌قاعده و کلماتی که التزامی می‌طلبند"},"labelHeader":{"it":"Elemento","ru":"Элемент","de":"Element","en":"Item","uk":"Елемент","fa":"عنصر"},"columns":[{"it":"Forma / trigger","ru":"Форма / триггер","de":"Form / Auslöser","en":"Form / trigger","uk":"Форма / тригер","fa":"صورت / محرک"},{"it":"Uso","ru":"Употребление","de":"Gebrauch","en":"Use","uk":"Вживання","fa":"کاربرد"}],"rows":[{"label":{"it":"essere","ru":"essere (быть)","de":"essere (sein)","en":"essere (to be)","uk":"essere (бути)","fa":"essere (بودن)"},"cells":["che io sia, che loro siano","che sia vero"]},{"label":{"it":"avere","ru":"avere (иметь)","de":"avere (haben)","en":"avere (to have)","uk":"avere (мати)","fa":"avere (داشتن)"},"cells":["che io abbia, che loro abbiano","che tu abbia ragione"]},{"label":{"it":"fare / andare","ru":"fare / andare","de":"fare / andare","en":"fare / andare","uk":"fare / andare","fa":"fare / andare"},"cells":["che io faccia, che io vada","che faccia bel tempo"]},{"label":{"it":"penso che","ru":"penso che (думаю, что)","de":"penso che (ich denke, dass)","en":"penso che (I think that)","uk":"penso che (я думаю, що)","fa":"penso che (فکر می‌کنم که)"},"cells":["opinione / dubbio","Penso che sia giusto"]},{"label":{"it":"benché / sebbene","ru":"benché (хотя)","de":"benché (obwohl)","en":"benché (although)","uk":"benché (хоча)","fa":"benché (اگرچه)"},"cells":["concessione","Benché piova, esco"]},{"label":{"it":"affinché / perché","ru":"affinché (чтобы)","de":"affinché (damit)","en":"affinché (so that)","uk":"affinché (щоб)","fa":"affinché (تا اینکه)"},"cells":["scopo","Parlo affinché tu capisca"]},{"label":{"it":"so che (indicativo)","ru":"so che (знаю, что — изъявит.)","de":"so che (ich weiß, dass — Indikativ)","en":"so che (I know that — indicative)","uk":"so che (я знаю, що — дійсний)","fa":"so che (می‌دانم که — اخباری)"},"cells":["certezza → indicativo","So che è vero"]}]}],"examples":[{"it":"Penso che tu abbia ragione.","ru":"Я думаю, что ты прав.","de":"Ich glaube, dass du recht hast.","en":"I think you're right.","uk":"Я думаю, що ти маєш рацію.","fa":"فکر می‌کنم حق با توست."},{"it":"È importante che voi arriviate in orario.","ru":"Важно, чтобы вы пришли вовремя.","de":"Es ist wichtig, dass ihr pünktlich kommt.","en":"It's important that you arrive on time.","uk":"Важливо, щоб ви прийшли вчасно.","fa":"مهم است که شما به‌موقع برسید."},{"it":"Benché sia stanco, continua a lavorare.","ru":"Хотя он устал, он продолжает работать.","de":"Obwohl er müde ist, arbeitet er weiter.","en":"Although he is tired, he keeps working.","uk":"Хоча він втомлений, він продовжує працювати.","fa":"با اینکه خسته است، به کار ادامه می‌دهد."}],"hints":{"ru":"Три лица единственного числа совпадают, поэтому местоимение или «che io/tu/lui» часто нужно для ясности. Уверенность (so che, è vero che) требует изъявительного, а не сослагательного.","de":"Die drei Singularpersonen sind identisch, daher braucht man oft das Pronomen oder «che io/tu/lui» zur Klarheit. Gewissheit (so che, è vero che) verlangt den Indikativ, nicht den Konjunktiv.","en":"The three singular persons are identical, so the pronoun or ‘che io/tu/lui' is often needed for clarity. Certainty (so che, è vero che) takes the indicative, not the subjunctive.","uk":"Три особи однини збігаються, тому займенник або «che io/tu/lui» часто потрібен для ясності. Впевненість (so che, è vero che) вимагає дійсного способу, а не кон'юнктива.","fa":"سه شخص مفرد یکسان‌اند، پس اغلب برای وضوح به ضمیر یا «che io/tu/lui» نیاز است. یقین (so che, è vero che) وجه اخباری می‌گیرد، نه التزامی."}},
{"id":"pronomi-relativi","icon":"🔗","level":"B1","title":{"it":"I pronomi relativi","ru":"Относительные местоимения","de":"Die Relativpronomen","en":"Relative pronouns","uk":"Відносні займенники","fa":"ضمایر موصولی"},"intro":{"it":"I pronomi relativi collegano due frasi riferendosi a un nome. «Che» è invariabile e vale come soggetto o oggetto (il libro che leggo). Dopo una preposizione si usa «cui» (la ragazza di cui parlo) o «il/la quale». «Chi» significa «colui che / la persona che» e regge il verbo al singolare.","ru":"Относительные местоимения соединяют два предложения, отсылая к существительному. «Che» неизменяемо и выступает как подлежащее или дополнение (il libro che leggo — книга, которую я читаю). После предлога используется «cui» (la ragazza di cui parlo) или «il/la quale». «Chi» значит «тот, кто / человек, который» и требует глагола в единственном числе.","de":"Relativpronomen verbinden zwei Sätze und beziehen sich auf ein Nomen. «Che» ist unveränderlich und dient als Subjekt oder Objekt (il libro che leggo — das Buch, das ich lese). Nach einer Präposition verwendet man «cui» (la ragazza di cui parlo) oder «il/la quale». «Chi» bedeutet «derjenige, der / die Person, die» und steht mit dem Verb im Singular.","en":"Relative pronouns join two clauses by referring to a noun. ‘Che' is invariable and works as subject or object (il libro che leggo — the book that I read). After a preposition use ‘cui' (la ragazza di cui parlo) or ‘il/la quale'. ‘Chi' means ‘the one who / the person who' and takes a singular verb.","uk":"Відносні займенники з'єднують два речення, відсилаючи до іменника. «Che» незмінне й виступає як підмет або додаток (il libro che leggo — книга, яку я читаю). Після прийменника вживають «cui» (la ragazza di cui parlo) або «il/la quale». «Chi» означає «той, хто / людина, яка» і вимагає дієслова в однині.","fa":"ضمایر موصولی دو جمله را با اشاره به یک اسم به هم پیوند می‌دهند. «che» تغییرناپذیر است و به‌عنوان فاعل یا مفعول کار می‌کند (il libro che leggo — کتابی که می‌خوانم). پس از حرف اضافه از «cui» (la ragazza di cui parlo) یا «il/la quale» استفاده می‌شود. «chi» یعنی «کسی که» و فعل مفرد می‌گیرد."},"tables":[{"caption":{"it":"I quattro pronomi relativi","ru":"Четыре относительных местоимения","de":"Die vier Relativpronomen","en":"The four relative pronouns","uk":"Чотири відносні займенники","fa":"چهار ضمیر موصولی"},"labelHeader":{"it":"Pronome","ru":"Местоимение","de":"Pronomen","en":"Pronoun","uk":"Займенник","fa":"ضمیر"},"columns":[{"it":"Funzione","ru":"Функция","de":"Funktion","en":"Function","uk":"Функція","fa":"نقش"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"che","ru":"che","de":"che","en":"che","uk":"che","fa":"che"},"cells":["soggetto / oggetto, invariabile","Il treno che parte alle otto"]},{"label":{"it":"cui","ru":"cui","de":"cui","en":"cui","uk":"cui","fa":"cui"},"cells":["dopo preposizione","La città in cui vivo"]},{"label":{"it":"il/la quale","ru":"il/la quale","de":"il/la quale","en":"il/la quale","uk":"il/la quale","fa":"il/la quale"},"cells":["formale, concorda in genere/numero","Il medico dal quale vado"]},{"label":{"it":"chi","ru":"chi","de":"chi","en":"chi","uk":"chi","fa":"chi"},"cells":["colui che (persone, singolare)","Chi dorme non piglia pesci"]}]},{"caption":{"it":"«cui» con preposizioni e il «cui» possessivo","ru":"«cui» с предлогами и притяжательное «cui»","de":"«cui» mit Präpositionen und das possessive «cui»","en":"‘cui' with prepositions and possessive ‘cui'","uk":"«cui» з прийменниками та присвійне «cui»","fa":"«cui» با حروف اضافه و «cui» ملکی"},"labelHeader":{"it":"Struttura","ru":"Структура","de":"Struktur","en":"Structure","uk":"Структура","fa":"ساختار"},"columns":[{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"di cui","ru":"di cui (о котором)","de":"di cui (von dem)","en":"di cui (of which)","uk":"di cui (про який)","fa":"di cui (که دربارهٔ آن)"},"cells":["Il film di cui parli"]},{"label":{"it":"a cui","ru":"a cui (которому)","de":"a cui (dem)","en":"a cui (to whom)","uk":"a cui (якому)","fa":"a cui (که به آن)"},"cells":["L'amico a cui scrivo"]},{"label":{"it":"in cui","ru":"in cui (в котором)","de":"in cui (in dem)","en":"in cui (in which)","uk":"in cui (в якому)","fa":"in cui (که در آن)"},"cells":["L'anno in cui sono nato"]},{"label":{"it":"con cui","ru":"con cui (с которым)","de":"con cui (mit dem)","en":"con cui (with whom)","uk":"con cui (з яким)","fa":"con cui (که با آن)"},"cells":["La penna con cui scrivo"]},{"label":{"it":"il cui (possessivo)","ru":"il cui (чей)","de":"il cui (dessen)","en":"il cui (whose)","uk":"il cui (чий)","fa":"il cui (که ... ِ او)"},"cells":["Lo scrittore il cui libro amo"]}]}],"examples":[{"it":"La ragazza che parla è mia sorella.","ru":"Девушка, которая говорит, — моя сестра.","de":"Das Mädchen, das spricht, ist meine Schwester.","en":"The girl who is speaking is my sister.","uk":"Дівчина, яка говорить, — моя сестра.","fa":"دختری که حرف می‌زند خواهر من است."},{"it":"Questo è l'argomento di cui volevo parlarti.","ru":"Это тема, о которой я хотел с тобой поговорить.","de":"Das ist das Thema, über das ich mit dir sprechen wollte.","en":"This is the topic I wanted to talk to you about.","uk":"Це тема, про яку я хотів з тобою поговорити.","fa":"این همان موضوعی است که می‌خواستم دربارهٔ آن با تو صحبت کنم."},{"it":"Chi cerca trova.","ru":"Кто ищет, тот находит.","de":"Wer sucht, der findet.","en":"Whoever seeks, finds.","uk":"Хто шукає, той знаходить.","fa":"هر که بجوید، می‌یابد."}],"hints":{"ru":"«Che» никогда не ставится после предлога — тогда только «cui» или «il quale»: не «di che», а «di cui». «Chi» относится к людям и всегда единственного числа.","de":"«Che» steht nie nach einer Präposition — dann nur «cui» oder «il quale»: nicht «di che», sondern «di cui». «Chi» bezieht sich auf Personen und ist immer Singular.","en":"‘Che' never follows a preposition — use ‘cui' or ‘il quale' instead: not ‘di che' but ‘di cui'. ‘Chi' refers to people and is always singular.","uk":"«Che» ніколи не стоїть після прийменника — тоді лише «cui» або «il quale»: не «di che», а «di cui». «Chi» стосується людей і завжди в однині.","fa":"«che» هرگز پس از حرف اضافه نمی‌آید — به‌جای آن «cui» یا «il quale»: نه «di che» بلکه «di cui». «chi» به افراد اشاره دارد و همیشه مفرد است."}},
{"id":"imperativo","icon":"📣","level":"B1","title":{"it":"L'imperativo","ru":"Повелительное наклонение","de":"Der Imperativ","en":"The imperative","uk":"Наказовий спосіб","fa":"وجه امری"},"intro":{"it":"L'imperativo dà ordini, consigli e istruzioni. Ha forme per tu, noi e voi; la forma di cortesia «Lei» usa il congiuntivo presente (Scusi! Prenda!). I pronomi si attaccano alla fine dei comandi informali (dimmi!, alzati!) ma precedono la forma di cortesia (mi dica). Il negativo del «tu» è «non» + infinito (non parlare!).","ru":"Повелительное наклонение выражает приказы, советы и инструкции. У него есть формы для tu, noi и voi; вежливая форма «Lei» использует настоящее сослагательное (Scusi! Prenda!). Местоимения присоединяются к концу неформальных команд (dimmi! — скажи мне!, alzati! — встань!), но предшествуют вежливой форме (mi dica). Отрицание «tu» — «non» + инфинитив (non parlare! — не говори!).","de":"Der Imperativ drückt Befehle, Ratschläge und Anweisungen aus. Er hat Formen für tu, noi und voi; die Höflichkeitsform «Lei» verwendet den Konjunktiv Präsens (Scusi! Prenda!). Pronomen werden an informelle Befehle angehängt (dimmi!, alzati!), stehen aber vor der Höflichkeitsform (mi dica). Die Verneinung des «tu» ist «non» + Infinitiv (non parlare!).","en":"The imperative gives orders, advice and instructions. It has forms for tu, noi and voi; the polite ‘Lei' form uses the present subjunctive (Scusi! Prenda!). Pronouns attach to the end of informal commands (dimmi!, alzati!) but come before the polite form (mi dica). The negative ‘tu' is ‘non' + infinitive (non parlare!).","uk":"Наказовий спосіб виражає накази, поради й інструкції. Він має форми для tu, noi і voi; ввічлива форма «Lei» використовує теперішній кон'юнктив (Scusi! Prenda!). Займенники приєднуються до кінця неформальних команд (dimmi!, alzati!), але передують ввічливій формі (mi dica). Заперечення «tu» — «non» + інфінітив (non parlare!).","fa":"وجه امری برای دستور، توصیه و راهنمایی به کار می‌رود. صورت‌هایی برای tu، noi و voi دارد؛ صورت مؤدبانهٔ «Lei» از التزامی حال استفاده می‌کند (Scusi! Prenda!). ضمایر به انتهای دستورهای غیررسمی می‌چسبند (dimmi!, alzati!) اما پیش از صورت مؤدبانه می‌آیند (mi dica). منفیِ «tu» به‌صورت «non» + مصدر است (non parlare!)."},"tables":[{"caption":{"it":"Imperativo: parlare, prendere, dormire, finire","ru":"Повелительное: parlare, prendere, dormire, finire","de":"Imperativ: parlare, prendere, dormire, finire","en":"Imperative: parlare, prendere, dormire, finire","uk":"Наказовий: parlare, prendere, dormire, finire","fa":"امری: parlare, prendere, dormire, finire"},"labelHeader":{"it":"Persona","ru":"Лицо","de":"Person","en":"Person","uk":"Особа","fa":"شخص"},"columns":[{"it":"parlare","ru":"parlare (говорить)","de":"parlare (sprechen)","en":"parlare (to speak)","uk":"parlare (говорити)","fa":"parlare (حرف زدن)"},{"it":"prendere","ru":"prendere (брать)","de":"prendere (nehmen)","en":"prendere (to take)","uk":"prendere (брати)","fa":"prendere (گرفتن)"},{"it":"finire (-isc-)","ru":"finire (заканчивать)","de":"finire (beenden)","en":"finire (to finish)","uk":"finire (закінчувати)","fa":"finire (تمام کردن)"}],"rows":[{"label":{"it":"tu","ru":"tu (ты)","de":"tu (du)","en":"tu (you)","uk":"tu (ти)","fa":"tu (تو)"},"cells":["parla!","prendi!","finisci!"]},{"label":{"it":"Lei (formale)","ru":"Lei (вежл.)","de":"Lei (höflich)","en":"Lei (polite)","uk":"Lei (ввічл.)","fa":"Lei (مؤدبانه)"},"cells":["parli!","prenda!","finisca!"]},{"label":{"it":"noi","ru":"noi (мы)","de":"noi (wir)","en":"noi (we)","uk":"noi (ми)","fa":"noi (ما)"},"cells":["parliamo!","prendiamo!","finiamo!"]},{"label":{"it":"voi","ru":"voi (вы)","de":"voi (ihr)","en":"voi (you pl.)","uk":"voi (ви)","fa":"voi (شما)"},"cells":["parlate!","prendete!","finite!"]},{"label":{"it":"tu negativo","ru":"tu отриц.","de":"tu verneint","en":"tu negative","uk":"tu заперечний","fa":"tu منفی"},"cells":["non parlare!","non prendere!","non finire!"]}]},{"caption":{"it":"Irregolari, forme tronche e pronomi","ru":"Неправильные, усечённые формы и местоимения","de":"Unregelmäßige, verkürzte Formen und Pronomen","en":"Irregulars, shortened forms and pronouns","uk":"Неправильні, скорочені форми та займенники","fa":"بی‌قاعده‌ها، صورت‌های کوتاه و ضمایر"},"labelHeader":{"it":"Verbo / caso","ru":"Глагол / случай","de":"Verb / Fall","en":"Verb / case","uk":"Дієслово / випадок","fa":"فعل / مورد"},"columns":[{"it":"Forma (tu)","ru":"Форма (tu)","de":"Form (tu)","en":"Form (tu)","uk":"Форма (tu)","fa":"صورت (tu)"},{"it":"Con pronome","ru":"С местоимением","de":"Mit Pronomen","en":"With pronoun","uk":"Із займенником","fa":"با ضمیر"}],"rows":[{"label":{"it":"essere","ru":"essere (быть)","de":"essere (sein)","en":"essere (to be)","uk":"essere (бути)","fa":"essere (بودن)"},"cells":["sii!","siate!"]},{"label":{"it":"avere","ru":"avere (иметь)","de":"avere (haben)","en":"avere (to have)","uk":"avere (мати)","fa":"avere (داشتن)"},"cells":["abbi!","abbiate!"]},{"label":{"it":"andare","ru":"andare (идти)","de":"andare (gehen)","en":"andare (to go)","uk":"andare (йти)","fa":"andare (رفتن)"},"cells":["va' / vai!","vacci!"]},{"label":{"it":"dare / dire","ru":"dare / dire (давать / говорить)","de":"dare / dire (geben / sagen)","en":"dare / dire (give / tell)","uk":"dare / dire (давати / казати)","fa":"dare / dire (دادن / گفتن)"},"cells":["da' / di'!","dimmi!"]},{"label":{"it":"fare / stare","ru":"fare / stare (делать / быть)","de":"fare / stare (machen / bleiben)","en":"fare / stare (do / stay)","uk":"fare / stare (робити / бути)","fa":"fare / stare (کردن / ماندن)"},"cells":["fa' / sta'!","fallo!"]},{"label":{"it":"riflessivo (tu)","ru":"возвратный (tu)","de":"reflexiv (tu)","en":"reflexive (tu)","uk":"зворотний (tu)","fa":"انعکاسی (tu)"},"cells":["alzati!","svegliati!"]},{"label":{"it":"Lei riflessivo","ru":"Lei возвратный","de":"Lei reflexiv","en":"Lei reflexive","uk":"Lei зворотний","fa":"Lei انعکاسی"},"cells":["si accomodi!","mi dica!"]}]}],"examples":[{"it":"Scusi, mi dica dov'è la stazione.","ru":"Извините, скажите мне, где вокзал.","de":"Entschuldigung, sagen Sie mir, wo der Bahnhof ist.","en":"Excuse me, tell me where the station is.","uk":"Вибачте, скажіть мені, де вокзал.","fa":"ببخشید، به من بگویید ایستگاه کجاست."},{"it":"Non preoccuparti, andrà tutto bene!","ru":"Не волнуйся, всё будет хорошо!","de":"Mach dir keine Sorgen, alles wird gut!","en":"Don't worry, everything will be fine!","uk":"Не хвилюйся, все буде добре!","fa":"نگران نباش، همه‌چیز خوب پیش می‌رود!"},{"it":"Prendiamo un caffè e parliamone!","ru":"Давайте выпьем кофе и поговорим об этом!","de":"Lass uns einen Kaffee trinken und darüber reden!","en":"Let's have a coffee and talk about it!","uk":"Випиймо кави і поговорімо про це!","fa":"بیایید یک قهوه بنوشیم و دربارهٔ آن حرف بزنیم!"}],"hints":{"ru":"У односложных глаголов (va', da', fa', sta', di') местоимение удваивает начальную согласную: fa'+lo → fallo, da'+mi → dammi (кроме gli: dagli).","de":"Bei den einsilbigen Formen (va', da', fa', sta', di') verdoppelt das Pronomen den Anfangskonsonanten: fa'+lo → fallo, da'+mi → dammi (außer gli: dagli).","en":"With the one-syllable forms (va', da', fa', sta', di') the pronoun doubles its initial consonant: fa'+lo → fallo, da'+mi → dammi (except gli: dagli).","uk":"У односкладових форм (va', da', fa', sta', di') займенник подвоює початкову приголосну: fa'+lo → fallo, da'+mi → dammi (крім gli: dagli).","fa":"با صورت‌های تک‌هجایی (va', da', fa', sta', di') ضمیر همخوان آغازینش را دوتا می‌کند: fa'+lo → fallo، da'+mi → dammi (به‌جز gli: dagli)."}},
{"id":"periodo-ipotetico","icon":"🔀","level":"B1","title":{"it":"Il periodo ipotetico (le frasi con «se»)","ru":"Условный период (предложения с «se»)","de":"Der Konditionalsatz (Sätze mit «se»)","en":"The conditional sentence (clauses with «se»)","uk":"Умовний період (речення зі «se»)","fa":"جملهٔ شرطی (جمله‌ها با «se»)"},"intro":{"it":"Il periodo ipotetico collega una condizione (protasi con «se») a una conseguenza (apodosi). Con la realtà si usa l'indicativo: «se + presente → presente/futuro». Con la possibilità si usa «se + congiuntivo imperfetto → condizionale presente». Con l'irrealtà: «se + congiuntivo trapassato → condizionale passato».","ru":"Условный период связывает условие (протасис с «se») со следствием (аподосис). Для реальности используется изъявительное наклонение: «se + настоящее → настоящее/будущее». Для возможности: «se + congiuntivo imperfetto → condizionale presente». Для нереальности: «se + congiuntivo trapassato → condizionale passato».","de":"Der Konditionalsatz verbindet eine Bedingung (Protasis mit «se») mit einer Folge (Apodosis). Für die Realität nimmt man den Indikativ: «se + Präsens → Präsens/Futur». Für die Möglichkeit: «se + Congiuntivo Imperfetto → Condizionale Presente». Für die Irrealität: «se + Congiuntivo Trapassato → Condizionale Passato».","en":"The conditional sentence links a condition (protasis with «se») to a consequence (apodosis). For reality you use the indicative: «se + present → present/future». For possibility: «se + imperfect subjunctive → present conditional». For unreality: «se + pluperfect subjunctive → past conditional».","uk":"Умовний період поєднує умову (протазис зі «se») з наслідком (аподозис). Для реальності вживають дійсний спосіб: «se + теперішній → теперішній/майбутній». Для можливості: «se + congiuntivo imperfetto → condizionale presente». Для нереальності: «se + congiuntivo trapassato → condizionale passato».","fa":"جملهٔ شرطی یک شرط (بند «se») را به یک نتیجه پیوند می‌دهد. برای واقعیت از وجه اخباری استفاده می‌شود: «se + حال → حال/آینده». برای امکان: «se + وجه التزامی ماضی استمراری → شرطی حال». برای غیرواقعیت: «se + وجه التزامی بعید → شرطی گذشته»."},"tables":[{"caption":{"it":"I tre tipi di periodo ipotetico","ru":"Три типа условного периода","de":"Die drei Typen des Konditionalsatzes","en":"The three types of conditional sentence","uk":"Три типи умовного періоду","fa":"سه نوع جملهٔ شرطی"},"labelHeader":{"it":"Tipo","ru":"Тип","de":"Typ","en":"Type","uk":"Тип","fa":"نوع"},"columns":[{"it":"Protasi (se…)","ru":"Протасис (se…)","de":"Protasis (se…)","en":"Protasis (se…)","uk":"Протазис (se…)","fa":"بند شرط (se…)"},{"it":"Apodosi","ru":"Аподосис","de":"Apodosis","en":"Apodosis","uk":"Аподозис","fa":"بند جواب"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"Realtà","ru":"Реальность","de":"Realität","en":"Reality","uk":"Реальність","fa":"واقعیت"},"cells":["se + presente","presente / futuro","Se piove, resto a casa."]},{"label":{"it":"Possibilità","ru":"Возможность","de":"Möglichkeit","en":"Possibility","uk":"Можливість","fa":"امکان"},"cells":["se + cong. imperfetto","condizionale presente","Se piovesse, resterei a casa."]},{"label":{"it":"Irrealtà","ru":"Нереальность","de":"Irrealität","en":"Unreality","uk":"Нереальність","fa":"غیرواقعیت"},"cells":["se + cong. trapassato","condizionale passato","Se avesse piovuto, sarei restato a casa."]}]}],"examples":[{"it":"Se studi, passerai l'esame.","ru":"Если будешь учиться, сдашь экзамен.","de":"Wenn du lernst, wirst du die Prüfung bestehen.","en":"If you study, you will pass the exam.","uk":"Якщо ти вчитимешся, складеш іспит.","fa":"اگر درس بخوانی، امتحان را قبول می‌شوی."},{"it":"Se avessi tempo, verrei con te.","ru":"Если бы у меня было время, я пошёл бы с тобой.","de":"Wenn ich Zeit hätte, würde ich mit dir kommen.","en":"If I had time, I would come with you.","uk":"Якби я мав час, я б пішов з тобою.","fa":"اگر وقت داشتم، با تو می‌آمدم."},{"it":"Se fossi partito prima, non avresti perso il treno.","ru":"Если бы ты выехал раньше, не опоздал бы на поезд.","de":"Wenn du früher losgefahren wärst, hättest du den Zug nicht verpasst.","en":"If you had left earlier, you wouldn't have missed the train.","uk":"Якби ти виїхав раніше, не спізнився б на потяг.","fa":"اگر زودتر راه افتاده بودی، قطار را از دست نمی‌دادی."}],"hints":{"ru":"После «se» НИКОГДА не ставится условное наклонение (condizionale) — только настоящее время, congiuntivo imperfetto или trapassato.","de":"Nach «se» steht NIE das Condizionale — nur Präsens, Congiuntivo Imperfetto oder Trapassato.","en":"Never use the conditional after «se» — only present, imperfect or pluperfect subjunctive.","uk":"Після «se» НІКОЛИ не ставлять condizionale — лише теперішній, congiuntivo imperfetto або trapassato.","fa":"بعد از «se» هرگز از شرطی (condizionale) استفاده نکنید — فقط حال، التزامی ماضی استمراری یا بعید."}},
{"id":"gerundio-stare","icon":"🏃","level":"B1","title":{"it":"Il gerundio e «stare + gerundio»","ru":"Герундий и «stare + gerundio»","de":"Das Gerundium und «stare + Gerundium»","en":"The gerund and «stare + gerund»","uk":"Герундій і «stare + gerundio»","fa":"جروندیو و «stare + جروندیو»"},"intro":{"it":"Il gerundio si forma con -ando (verbi in -are) e -endo (verbi in -ere/-ire): parlando, scrivendo, dormendo. Con «stare + gerundio» si esprime un'azione in corso (progressivo): «sto mangiando». Da solo, il gerundio indica modo, causa o tempo: «Correndo, sono caduto» (mentre correvo).","ru":"Герундий образуется с -ando (глаголы на -are) и -endo (глаголы на -ere/-ire): parlando, scrivendo, dormendo. С «stare + gerundio» выражается действие в процессе (прогрессив): «sto mangiando». Самостоятельно герундий указывает на образ действия, причину или время: «Correndo, sono caduto» (пока бежал).","de":"Das Gerundium bildet man mit -ando (Verben auf -are) und -endo (Verben auf -ere/-ire): parlando, scrivendo, dormendo. Mit «stare + Gerundium» drückt man eine laufende Handlung aus (Verlaufsform): «sto mangiando». Allein steht das Gerundium für Art, Ursache oder Zeit: «Correndo, sono caduto» (während ich lief).","en":"The gerund is formed with -ando (‑are verbs) and -endo (‑ere/‑ire verbs): parlando, scrivendo, dormendo. With «stare + gerund» you express an ongoing action (progressive): «sto mangiando». On its own the gerund shows manner, cause or time: «Correndo, sono caduto» (while running).","uk":"Герундій утворюється з -ando (дієслова на -are) і -endo (дієслова на -ere/-ire): parlando, scrivendo, dormendo. Зі «stare + gerundio» виражається дія у процесі (прогресив): «sto mangiando». Самостійно герундій вказує на спосіб, причину або час: «Correndo, sono caduto» (поки біг).","fa":"جروندیو با -ando (افعال -are) و -endo (افعال -ere/-ire) ساخته می‌شود: parlando, scrivendo, dormendo. با «stare + جروندیو» عملی در حال انجام بیان می‌شود: «sto mangiando». به‌تنهایی، جروندیو حالت، علت یا زمان را نشان می‌دهد: «Correndo, sono caduto» (هنگام دویدن)."},"tables":[{"caption":{"it":"Formazione del gerundio","ru":"Образование герундия","de":"Bildung des Gerundiums","en":"Formation of the gerund","uk":"Утворення герундія","fa":"ساخت جروندیو"},"labelHeader":{"it":"Verbo","ru":"Глагол","de":"Verb","en":"Verb","uk":"Дієслово","fa":"فعل"},"columns":[{"it":"Gerundio","ru":"Герундий","de":"Gerundium","en":"Gerund","uk":"Герундій","fa":"جروندیو"},{"it":"stare + gerundio","ru":"stare + gerundio","de":"stare + Gerundium","en":"stare + gerund","uk":"stare + gerundio","fa":"stare + جروندیو"}],"rows":[{"label":{"it":"parlare","ru":"parlare (говорить)","de":"parlare (sprechen)","en":"parlare (to speak)","uk":"parlare (говорити)","fa":"parlare (صحبت کردن)"},"cells":["parlando","sto parlando"]},{"label":{"it":"scrivere","ru":"scrivere (писать)","de":"scrivere (schreiben)","en":"scrivere (to write)","uk":"scrivere (писати)","fa":"scrivere (نوشتن)"},"cells":["scrivendo","sto scrivendo"]},{"label":{"it":"dormire","ru":"dormire (спать)","de":"dormire (schlafen)","en":"dormire (to sleep)","uk":"dormire (спати)","fa":"dormire (خوابیدن)"},"cells":["dormendo","sto dormendo"]},{"label":{"it":"fare (irregolare)","ru":"fare (неправ.)","de":"fare (unregelmäßig)","en":"fare (irregular)","uk":"fare (неправ.)","fa":"fare (بی‌قاعده)"},"cells":["facendo","sto facendo"]}]}],"examples":[{"it":"Che cosa stai facendo? — Sto guardando un film.","ru":"Что ты делаешь? — Смотрю фильм.","de":"Was machst du gerade? — Ich schaue einen Film.","en":"What are you doing? — I'm watching a film.","uk":"Що ти робиш? — Дивлюся фільм.","fa":"چه کار می‌کنی؟ — دارم فیلم می‌بینم."},{"it":"Ho imparato l'italiano guardando le serie TV.","ru":"Я выучил итальянский, смотря сериалы.","de":"Ich habe Italienisch gelernt, indem ich Serien schaute.","en":"I learned Italian by watching TV series.","uk":"Я вивчив італійську, дивлячись серіали.","fa":"با تماشای سریال‌ها ایتالیایی یاد گرفتم."},{"it":"Essendo stanco, sono andato a dormire presto.","ru":"Будучи усталым, я лёг спать рано.","de":"Da ich müde war, ging ich früh schlafen.","en":"Being tired, I went to bed early.","uk":"Будучи втомленим, я ліг спати рано.","fa":"چون خسته بودم، زود خوابیدم."}],"hints":{"ru":"С «stare + gerundio» местоимение крепится к «stare» или к герундию: «Lo sto guardando» или «Sto guardandolo». Оба варианта верны.","de":"Bei «stare + Gerundium» kann das Pronomen an «stare» oder ans Gerundium: «Lo sto guardando» oder «Sto guardandolo». Beides richtig.","en":"With «stare + gerund» the pronoun attaches to «stare» or to the gerund: «Lo sto guardando» or «Sto guardandolo». Both are correct.","uk":"Зі «stare + gerundio» займенник кріпиться до «stare» або до герундія: «Lo sto guardando» або «Sto guardandolo». Обидва правильні.","fa":"با «stare + جروندیو» ضمیر به «stare» یا به جروندیو می‌چسبد: «Lo sto guardando» یا «Sto guardandolo». هر دو درست است."}},
{"id":"pronomi-combinati","icon":"🧩","level":"B1","title":{"it":"I pronomi combinati (doppi)","ru":"Комбинированные (двойные) местоимения","de":"Die kombinierten (doppelten) Pronomen","en":"Combined (double) object pronouns","uk":"Комбіновані (подвійні) займенники","fa":"ضمایر ترکیبی (دوگانه)"},"intro":{"it":"Quando un pronome indiretto e uno diretto compaiono insieme, l'indiretto viene prima e cambia forma: mi/ti/ci/vi → me/te/ce/ve; gli/le → glie- (unito, es. glielo). L'ordine è sempre «indiretto + diretto». Con «ne» (di ciò): «me ne», «gliene». Nei tempi composti il participio concorda con il pronome diretto: «Glieli ho dati».","ru":"Когда косвенное и прямое местоимения стоят вместе, косвенное идёт первым и меняет форму: mi/ti/ci/vi → me/te/ce/ve; gli/le → glie- (слитно, напр. glielo). Порядок всегда «косвенное + прямое». С «ne» (об этом): «me ne», «gliene». В сложных временах причастие согласуется с прямым местоимением: «Glieli ho dati».","de":"Wenn ein indirektes und ein direktes Pronomen zusammenstehen, kommt das indirekte zuerst und ändert die Form: mi/ti/ci/vi → me/te/ce/ve; gli/le → glie- (verbunden, z. B. glielo). Die Reihenfolge ist immer «indirekt + direkt». Mit «ne» (davon): «me ne», «gliene». In zusammengesetzten Zeiten richtet sich das Partizip nach dem direkten Pronomen: «Glieli ho dati».","en":"When an indirect and a direct pronoun appear together, the indirect comes first and changes form: mi/ti/ci/vi → me/te/ce/ve; gli/le → glie- (joined, e.g. glielo). The order is always «indirect + direct». With «ne» (of it): «me ne», «gliene». In compound tenses the participle agrees with the direct pronoun: «Glieli ho dati».","uk":"Коли непрямий і прямий займенники стоять разом, непрямий іде першим і змінює форму: mi/ti/ci/vi → me/te/ce/ve; gli/le → glie- (разом, напр. glielo). Порядок завжди «непрямий + прямий». З «ne» (про це): «me ne», «gliene». У складних часах дієприкметник узгоджується з прямим займенником: «Glieli ho dati».","fa":"وقتی ضمیر غیرمستقیم و مستقیم با هم می‌آیند، غیرمستقیم اول می‌آید و شکلش تغییر می‌کند: mi/ti/ci/vi → me/te/ce/ve؛ gli/le → glie- (چسبیده، مثل glielo). ترتیب همیشه «غیرمستقیم + مستقیم» است. با «ne» (از آن): «me ne»، «gliene». در زمان‌های مرکب، اسم مفعول با ضمیر مستقیم مطابقت می‌کند: «Glieli ho dati»."},"tables":[{"caption":{"it":"Combinazione dei pronomi","ru":"Комбинация местоимений","de":"Kombination der Pronomen","en":"Combination of pronouns","uk":"Комбінація займенників","fa":"ترکیب ضمایر"},"labelHeader":{"it":"Indiretto","ru":"Косвенное","de":"Indirekt","en":"Indirect","uk":"Непрямий","fa":"غیرمستقیم"},"columns":[{"it":"+ lo","ru":"+ lo","de":"+ lo","en":"+ lo","uk":"+ lo","fa":"+ lo"},{"it":"+ la","ru":"+ la","de":"+ la","en":"+ la","uk":"+ la","fa":"+ la"},{"it":"+ li / le","ru":"+ li / le","de":"+ li / le","en":"+ li / le","uk":"+ li / le","fa":"+ li / le"},{"it":"+ ne","ru":"+ ne","de":"+ ne","en":"+ ne","uk":"+ ne","fa":"+ ne"}],"rows":[{"label":{"it":"mi","ru":"mi (мне)","de":"mi (mir)","en":"mi (to me)","uk":"mi (мені)","fa":"mi (به من)"},"cells":["me lo","me la","me li / me le","me ne"]},{"label":{"it":"ti","ru":"ti (тебе)","de":"ti (dir)","en":"ti (to you)","uk":"ti (тобі)","fa":"ti (به تو)"},"cells":["te lo","te la","te li / te le","te ne"]},{"label":{"it":"gli / le","ru":"gli / le (ему/ей)","de":"gli / le (ihm/ihr)","en":"gli / le (to him/her)","uk":"gli / le (йому/їй)","fa":"gli / le (به او)"},"cells":["glielo","gliela","glieli / gliele","gliene"]},{"label":{"it":"ci","ru":"ci (нам)","de":"ci (uns)","en":"ci (to us)","uk":"ci (нам)","fa":"ci (به ما)"},"cells":["ce lo","ce la","ce li / ce le","ce ne"]}]}],"examples":[{"it":"Mi presti la macchina? — Sì, te la presto.","ru":"Одолжишь мне машину? — Да, одолжу её тебе.","de":"Leihst du mir das Auto? — Ja, ich leihe es dir.","en":"Will you lend me the car? — Yes, I'll lend it to you.","uk":"Позичиш мені авто? — Так, позичу його тобі.","fa":"ماشین را به من قرض می‌دهی؟ — بله، آن را به تو قرض می‌دهم."},{"it":"Hai dato il libro a Marco? — Sì, gliel'ho dato ieri.","ru":"Ты дал книгу Марко? — Да, я дал её ему вчера.","de":"Hast du Marco das Buch gegeben? — Ja, ich habe es ihm gestern gegeben.","en":"Did you give the book to Marco? — Yes, I gave it to him yesterday.","uk":"Ти дав книгу Марко? — Так, я дав її йому вчора.","fa":"کتاب را به مارکو دادی؟ — بله، دیروز آن را به او دادم."},{"it":"Vuoi del caffè? — Sì, dammene un po', per favore.","ru":"Хочешь кофе? — Да, дай мне немного, пожалуйста.","de":"Möchtest du Kaffee? — Ja, gib mir bitte etwas davon.","en":"Do you want some coffee? — Yes, give me a little of it, please.","uk":"Хочеш кави? — Так, дай мені трохи, будь ласка.","fa":"قهوه می‌خواهی؟ — بله، لطفاً کمی از آن به من بده."}],"hints":{"ru":"«gli» и «le» дают одну и ту же форму «glie-», поэтому «glielo» значит и «ему это», и «ей это» — контекст решает.","de":"«gli» und «le» ergeben dieselbe Form «glie-», daher heißt «glielo» sowohl «es ihm» als auch «es ihr» — der Kontext entscheidet.","en":"«gli» and «le» both become «glie-», so «glielo» means both «it to him» and «it to her» — context decides.","uk":"«gli» і «le» дають одну форму «glie-», тож «glielo» означає і «йому це», і «їй це» — вирішує контекст.","fa":"«gli» و «le» هر دو به «glie-» تبدیل می‌شوند، پس «glielo» هم «به او (مذکر)» و هم «به او (مؤنث)» معنی می‌دهد — بافت تعیین می‌کند."}},
{"id":"si-impersonale","icon":"👥","level":"B1","title":{"it":"Il «si» impersonale e passivante","ru":"«Si» безличное и пассивное","de":"Das unpersönliche und passivische «si»","en":"The impersonal and passivising «si»","uk":"«Si» безособове та пасивне","fa":"«si» غیرشخصی و مجهول‌ساز"},"intro":{"it":"Il «si» impersonale traduce «si fa / la gente fa» e usa il verbo alla 3ª persona singolare: «In Italia si mangia bene». Il «si» passivante regge un oggetto: se è singolare il verbo è singolare, se è plurale è plurale: «Si vende la casa» / «Si vendono le case». Nel discorso indiretto i tempi e i pronomi cambiano: «Ha detto: “Vengo”» → «Ha detto che veniva».","ru":"Безличное «si» переводит «делают / люди делают» и требует глагола в 3-м лице ед. ч.: «In Italia si mangia bene». Пассивное «si» управляет дополнением: если оно в ед. ч. — глагол в ед. ч., если во мн. ч. — во мн. ч.: «Si vende la casa» / «Si vendono le case». В косвенной речи меняются времена и местоимения: «Ha detto: “Vengo”» → «Ha detto che veniva».","de":"Das unpersönliche «si» übersetzt «man tut» und verlangt das Verb in der 3. Person Singular: «In Italia si mangia bene». Das passivische «si» regiert ein Objekt: ist es Singular, ist das Verb Singular, ist es Plural, Plural: «Si vende la casa» / «Si vendono le case». In der indirekten Rede ändern sich Zeiten und Pronomen: «Ha detto: “Vengo”» → «Ha detto che veniva».","en":"The impersonal «si» translates «one does / people do» and takes the verb in the 3rd person singular: «In Italia si mangia bene». The passivising «si» governs an object: if singular the verb is singular, if plural, plural: «Si vende la casa» / «Si vendono le case». In reported speech tenses and pronouns change: «Ha detto: “Vengo”» → «Ha detto che veniva».","uk":"Безособове «si» перекладає «роблять / люди роблять» і потребує дієслова в 3-й особі однини: «In Italia si mangia bene». Пасивне «si» керує додатком: якщо він в однині — дієслово в однині, якщо в множині — у множині: «Si vende la casa» / «Si vendono le case». У непрямій мові змінюються часи й займенники: «Ha detto: “Vengo”» → «Ha detto che veniva».","fa":"«si» غیرشخصی معادل «آدم انجام می‌دهد / مردم می‌کنند» است و فعل را در سوم‌شخص مفرد می‌آورد: «In Italia si mangia bene». «si» مجهول‌ساز یک مفعول می‌گیرد: اگر مفرد باشد فعل مفرد و اگر جمع باشد فعل جمع است: «Si vende la casa» / «Si vendono le case». در نقل‌قول غیرمستقیم زمان‌ها و ضمایر تغییر می‌کنند: «Ha detto: “Vengo”» → «Ha detto che veniva»."},"tables":[{"caption":{"it":"Impersonale vs passivante e discorso indiretto","ru":"Безличное и пассивное; косвенная речь","de":"Unpersönlich vs. passivisch; indirekte Rede","en":"Impersonal vs passivising; reported speech","uk":"Безособове й пасивне; непряма мова","fa":"غیرشخصی و مجهول؛ نقل‌قول غیرمستقیم"},"labelHeader":{"it":"Uso","ru":"Употребление","de":"Gebrauch","en":"Use","uk":"Вживання","fa":"کاربرد"},"columns":[{"it":"Struttura","ru":"Структура","de":"Struktur","en":"Structure","uk":"Структура","fa":"ساختار"},{"it":"Esempio","ru":"Пример","de":"Beispiel","en":"Example","uk":"Приклад","fa":"مثال"}],"rows":[{"label":{"it":"si impersonale","ru":"si безличное","de":"si unpersönlich","en":"impersonal si","uk":"si безособове","fa":"si غیرشخصی"},"cells":["si + verbo 3ª sing.","Qui si parla italiano."]},{"label":{"it":"si passivante (sing.)","ru":"si пассивное (ед.)","de":"si passivisch (Sg.)","en":"passivising si (sing.)","uk":"si пасивне (одн.)","fa":"si مجهول (مفرد)"},"cells":["si + verbo sing. + oggetto sing.","Si affitta un appartamento."]},{"label":{"it":"si passivante (plur.)","ru":"si пассивное (мн.)","de":"si passivisch (Pl.)","en":"passivising si (plur.)","uk":"si пасивне (мн.)","fa":"si مجهول (جمع)"},"cells":["si + verbo plur. + oggetto plur.","Si affittano appartamenti."]},{"label":{"it":"discorso indiretto","ru":"косвенная речь","de":"indirekte Rede","en":"reported speech","uk":"непряма мова","fa":"نقل‌قول غیرمستقیم"},"cells":["dice che + presente","Dice che è stanco."]}]}],"examples":[{"it":"In questo ristorante si mangia molto bene.","ru":"В этом ресторане очень хорошо кормят.","de":"In diesem Restaurant isst man sehr gut.","en":"In this restaurant one eats very well.","uk":"У цьому ресторані дуже добре годують.","fa":"در این رستوران آدم خیلی خوب غذا می‌خورد."},{"it":"In Italia si vendono molti gelati d'estate.","ru":"В Италии летом продают много мороженого.","de":"In Italien werden im Sommer viele Eis verkauft.","en":"In Italy a lot of ice cream is sold in summer.","uk":"В Італії влітку продають багато морозива.","fa":"در ایتالیا در تابستان بستنی زیادی فروخته می‌شود."},{"it":"Maria ha detto che sarebbe arrivata più tardi.","ru":"Мария сказала, что придёт позже.","de":"Maria sagte, dass sie später kommen würde.","en":"Maria said that she would arrive later.","uk":"Марія сказала, що прийде пізніше.","fa":"ماریا گفت که دیرتر خواهد رسید."}],"hints":{"ru":"После безличного «si» прилагательное ставится во множественном числе: «Quando si è stanchi, si dorme» — «когда устал, спишь».","de":"Nach unpersönlichem «si» steht das Adjektiv im Plural: «Quando si è stanchi, si dorme» — «wenn man müde ist, schläft man».","en":"After impersonal «si» the adjective goes in the plural: «Quando si è stanchi, si dorme» — «when one is tired, one sleeps».","uk":"Після безособового «si» прикметник стоїть у множині: «Quando si è stanchi, si dorme» — «коли втомлений, спиш».","fa":"بعد از «si» غیرشخصی، صفت جمع می‌آید: «Quando si è stanchi, si dorme» — «وقتی آدم خسته است، می‌خوابد»."}}
];
